import React, { useState } from 'react';
import { Button } from '@/components/ui/button';
import { 
  Bell, 
  BellOff, 
  Check, 
  CheckCheck, 
  Trash2, 
  Calendar,
  CreditCard,
  Clock,
  AlertCircle,
  MessageCircle,
  Video,
  Settings,
  User
} from 'lucide-react';
import { useNotifications } from '@/hooks/useNotifications';
import { formatDistanceToNow } from 'date-fns';
import { motion, AnimatePresence } from 'framer-motion';
import {
  Popover,
  PopoverContent,
  PopoverTrigger,
} from "@/components/ui/popover";
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { Badge } from '@/components/ui/badge';

interface NotificationDropdownProps {
  trigger?: React.ReactNode;
}

export const NotificationDropdown: React.FC<NotificationDropdownProps> = ({ trigger }) => {
  const {
    notifications,
    unreadCount,
    permission,
    loading,
    requestPermission,
    markAsRead,
    markAllAsRead,
    deleteNotification,
  } = useNotifications();

  const [isOpen, setIsOpen] = useState(false);
  const [filter, setFilter] = useState<'inbox' | 'general'>('inbox');

  // Filter notifications by type
  const filteredNotifications = notifications.filter(notification => {
    if (filter === 'inbox') {
      return ['booking', 'payment', 'puja', 'message', 'video'].includes(notification.type);
    }
    return ['system', 'reminder', 'update'].includes(notification.type);
  });

  const getTypeIcon = (type: string) => {
    switch (type) {
      case 'booking':
        return <Calendar className="w-4 h-4 text-blue-500" />;
      case 'payment':
        return <CreditCard className="w-4 h-4 text-green-500" />;
      case 'puja':
        return <span className="text-orange-500 text-sm">🕉️</span>;
      case 'reminder':
        return <Clock className="w-4 h-4 text-amber-500" />;
      case 'system':
        return <AlertCircle className="w-4 h-4 text-gray-500" />;
      case 'message':
        return <MessageCircle className="w-4 h-4 text-purple-500" />;
      case 'video':
        return <Video className="w-4 h-4 text-red-500" />;
      default:
        return <Bell className="w-4 h-4 text-orange-500" />;
    }
  };

