import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Loader2, CreditCard, Smartphone, MapPin, Globe } from 'lucide-react';
import { useLocation } from '@/hooks/useLocation';
import apiClient from '@/lib/api-client';

interface PaymentMethod {
  id: 'KHALTI' | 'STRIPE';
  name: string;
  description: string;
  icon: React.ReactNode;
  currency: string;
  recommended: boolean;
  available: boolean;
  processingFee: string;
}

interface SmartPaymentSelectorProps {
  bookingId: number;
  amount: number;
  onPaymentInitiated: (paymentUrl: string, gateway: string) => void;
  onError: (error: string) => void;
}

export const SmartPaymentSelector: React.FC<SmartPaymentSelectorProps> = ({
  bookingId,
  amount,
  onPaymentInitiated,
  onError
}) => {
  const { 
    country, 
    currency, 
    recommendedPaymentGateway, 
    getLocationContext 
  } = useLocation();

  const [selectedMethod, setSelectedMethod] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);
  const [exchangeRate, setExchangeRate] = useState<number | null>(null);

  useEffect(() => {
    // Auto-select recommended payment method
    setSelectedMethod(recommendedPaymentGateway);

    // Fetch exchange rate if needed
    if (currency !== 'NPR') {
      fetchExchangeRate();
    }
  }, [recommendedPaymentGateway, currency]);

  const fetchExchangeRate = async () => {
    try {
      const response = await apiClient.get('/payments/exchange-rate/', {
        params: { npr: amount }
      });
      setExchangeRate(response.data.rate);
    } catch (error) {
      console.error('Failed to fetch exchange rate:', error);
    }
  };

  const paymentMethods: PaymentMethod[] = [
    {
      id: 'KHALTI',
      name: 'Khalti',
      description: 'Digital wallet for Nepal',
      icon: <Smartphone className="w-5 h-5" />,
      currency: 'NPR',
      recommended: recommendedPaymentGateway === 'KHALTI',
      available: true,
      processingFee: '2.5%'
    },
    {
      id: 'STRIPE',
      name: 'Credit/Debit Card',
      description: 'International cards accepted',
      icon: <CreditCard className="w-5 h-5" />,
      currency: currency === 'NPR' ? 'USD' : currency,
      recommended: recommendedPaymentGateway === 'STRIPE',
      available: true,
      processingFee: '3.4% + $0.30'
    }
  ];

  const getConvertedAmount = (method: PaymentMethod) => {
    if (method.currency === 'NPR') {
      return { amount, currency: 'NPR', symbol: '₹' };
    }

    if (exchangeRate && method.currency === 'USD') {
      const usdAmount = amount / exchangeRate;
      return { 
        amount: usdAmount.toFixed(2), 
        currency: 'USD', 
        symbol: '$' 
      };
    }

    return { amount, currency: method.currency, symbol: '$' };
  };

  const handlePayment = async (methodId: string) => {
    setLoading(true);
    try {
      const locationContext = getLocationContext();

      const response = await apiClient.post('/payments/create-intent/', {
        booking_id: bookingId,
        gateway: methodId,
        currency: methodId === 'KHALTI' ? 'NPR' : currency,
        location_context: locationContext
      });

      if (response.data.success) {
        const paymentUrl = response.data.checkout_url || response.data.payment_url;
        onPaymentInitiated(paymentUrl, methodId);
      } else {
        onError('Failed to initiate payment');
      }
    } catch (error: any) {
      console.error('Payment initiation failed:', error);
      onError(error.response?.data?.error || 'Payment failed');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="space-y-6">
      {/* Location Context */}
      {country && (
        <Alert className="bg-blue-50 border-blue-200">
          <MapPin className="w-4 h-4" />
          <AlertDescription className="flex items-center gap-2">
            <Globe className="w-4 h-4" />
            Detected location: {country}
            <Badge variant="outline" className="ml-2">
              {currency} recommended
            </Badge>
          </AlertDescription>
        </Alert>
      )}

      {/* Payment Methods */}
      <div className="grid gap-4">
        {paymentMethods.map((method) => {
          const convertedAmount = getConvertedAmount(method);
          const isSelected = selectedMethod === method.id;
          const isRecommended = method.recommended;

          return (
            <Card 
              key={method.id}
              className={`cursor-pointer transition-all ${
                isSelected 
                  ? 'ring-2 ring-orange-500 border-orange-500' 
                  : 'hover:border-gray-300'
              } ${isRecommended ? 'bg-orange-50' : ''}`}
              onClick={() => setSelectedMethod(method.id)}
            >
              <CardContent className="p-4">
                <div className="flex items-center justify-between">
                  <div className="flex items-center gap-3">
                    <div className={`p-2 rounded-lg ${
                      method.id === 'KHALTI' ? 'bg-purple-100' : 'bg-blue-100'
                    }`}>
                      {method.icon}
                    </div>
                    <div>
                      <div className="flex items-center gap-2">
                        <h3 className="font-semibold">{method.name}</h3>
                        {isRecommended && (
                          <Badge className="bg-orange-500 text-white text-xs">
                            Recommended
                          </Badge>
                        )}
                      </div>
                      <p className="text-sm text-gray-600">{method.description}</p>
                      <p className="text-xs text-gray-500">
                        Processing fee: {method.processingFee}
                      </p>
                    </div>
                  </div>
                  <div className="text-right">
                    <div className="text-lg font-bold">
                      {convertedAmount.symbol}{convertedAmount.amount}
                    </div>
                    <div className="text-sm text-gray-500">
                      {convertedAmount.currency}
                    </div>
                  </div>
                </div>
              </CardContent>
            </Card>
          );
        })}
      </div>

      {/* Exchange Rate Info */}
      {exchangeRate && currency !== 'NPR' && (
        <div className="text-sm text-gray-600 bg-gray-50 p-3 rounded-lg">
          <div className="flex justify-between">
            <span>Exchange Rate:</span>
            <span>1 USD = ₹{exchangeRate.toFixed(2)} NPR</span>
          </div>
        </div>
      )}

      {/* Pay Button */}
      <Button
        onClick={() => selectedMethod && handlePayment(selectedMethod)}
        disabled={!selectedMethod || loading}
        className="w-full h-12 text-base bg-orange-600 hover:bg-orange-700"
      >
        {loading ? (
          <>
            <Loader2 className="w-5 h-5 animate-spin mr-2" />
            Processing...
          </>
        ) : (
          `Pay Now`
        )}
      </Button>
    </div>
  );
};

export default SmartPaymentSelector;

import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '@/hooks/useAuth';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { useToast } from '@/hooks/use-toast';
import apiClient from '@/lib/api-client';
import { deleteUserProfile } from '@/lib/api';
import { Loader2, Camera, User as UserIcon } from 'lucide-react';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { useNavigate } from 'react-router-dom';
import { ActionConfirmationDialog } from '@/components/common/ActionConfirmationDialog';

export const EditProfile = () => {
    const { user, refreshUser, logout } = useAuth();
    const { toast } = useToast();
    const navigate = useNavigate();
    const [loading, setLoading] = useState(false);
    const [deleting, setDeleting] = useState(false);
    const [showDeleteDialog, setShowDeleteDialog] = useState(false);
    const fileInputRef = useRef<HTMLInputElement>(null);
    const [previewUrl, setPreviewUrl] = useState<string | null>(null);
    const [selectedFile, setSelectedFile] = useState<File | null>(null);

    const [formData, setFormData] = useState({
        full_name: '',
        email: '',
        phone_number: '',
    });

    useEffect(() => {
        if (user) {
            setFormData({
                full_name: user.full_name || '',
                email: user.email || '',
                phone_number: user.phone_number || '',
            });
            // If user has a profile pic, set it as preview
            if (user.profile_pic) {
                setPreviewUrl(user.profile_pic);
            }
        }
    }, [user]);

    const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            setSelectedFile(file);
            const reader = new FileReader();
            reader.onloadend = () => {
                setPreviewUrl(reader.result as string);
            };
            reader.readAsDataURL(file);
        }
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            const data = new FormData();
            data.append('full_name', formData.full_name);
            data.append('email', formData.email);
            data.append('phone_number', formData.phone_number);

            if (selectedFile) {
                data.append('profile_pic', selectedFile);
            }

            await apiClient.patch('/users/profile/', data, {
                headers: {
                    'Content-Type': 'multipart/form-data',
                },
            });

            toast({ title: 'Success', description: 'Profile updated successfully' });
            refreshUser();
            setSelectedFile(null); // Clear selected file after success
        } catch (error: any) {
            toast({
                title: 'Error',
                description: error.response?.data?.detail || 'Failed to update profile',
                variant: 'destructive'
            });
        } finally {
            setLoading(false);
        }
    };

    const handleDeleteAccount = async () => {
        setDeleting(true);
        try {
            await deleteUserProfile();
            toast({
                title: 'Account deleted',
                description: 'Your account has been deleted successfully.'
            });
            logout();
            navigate('/');
        } catch (error: any) {
            toast({
                title: 'Delete failed',
                description: error?.response?.data?.detail || 'Could not delete your account.',
                variant: 'destructive',
            });
        } finally {
            setDeleting(false);
            setShowDeleteDialog(false);
        }
    };

    return (
        <form onSubmit={handleSubmit} className="space-y-8 max-w-lg">
            {/* Profile Photo Section */}
            <div className="flex flex-col items-center sm:flex-row sm:items-end gap-6 pb-4 border-b border-orange-50">
                <div className="relative group">
                    <Avatar className="w-32 h-32 border-4 border-white shadow-xl ring-1 ring-orange-100">
                        <AvatarImage src={previewUrl || undefined} className="object-cover" />
                        <AvatarFallback className="bg-orange-50 text-orange-200">
                            <UserIcon className="w-16 h-16" />
                        </AvatarFallback>
                    </Avatar>
                    <button
                        type="button"
                        onClick={() => fileInputRef.current?.click()}
                        className="absolute bottom-0 right-0 p-2 bg-[#FF6F00] text-white rounded-full shadow-lg hover:bg-orange-700 transition-all scale-90 group-hover:scale-100"
                    >
                        <Camera className="w-5 h-5" />
                    </button>
                    <input
                        type="file"
                        ref={fileInputRef}
                        onChange={handleFileChange}
                        accept="image/*"
                        className="hidden"
                    />
                </div>
                <div className="text-center sm:text-left space-y-1">
                    <h3 className="font-bold text-[#3E2723]">Profile Photo</h3>
                    <p className="text-xs text-muted-foreground">
                        JPG, PNG or WEBP. Max 2MB.
                    </p>
                    <Button
                        type="button"
                        variant="link"
                        className="p-0 h-auto text-[#FF6F00] font-bold text-xs"
                        onClick={() => fileInputRef.current?.click()}
                    >
                        Change Photo
                    </Button>
                </div>
            </div>

            <div className="space-y-4">
                <div className="space-y-2">
                    <Label htmlFor="full_name" className="text-xs font-black uppercase tracking-widest text-[#3E2723]/60">Full Name</Label>
                    <Input
                        id="full_name"
                        value={formData.full_name}
                        onChange={(e) => setFormData({ ...formData, full_name: e.target.value })}
                        required
                        className="rounded-xl border-orange-100 focus:ring-orange-200"
                    />
                </div>

                <div className="space-y-2">
                    <Label htmlFor="email" className="text-xs font-black uppercase tracking-widest text-[#3E2723]/60">Email</Label>
                    <Input
                        id="email"
                        type="email"
                        value={formData.email}
                        onChange={(e) => setFormData({ ...formData, email: e.target.value })}
                        className="rounded-xl border-orange-100 focus:ring-orange-200"
                    />
                </div>

                <div className="space-y-2">
                    <Label htmlFor="phone_number" className="text-xs font-black uppercase tracking-widest text-[#3E2723]/60">Phone Number</Label>
                    <Input
                        id="phone_number"
                        value={formData.phone_number}
                        onChange={(e) => setFormData({ ...formData, phone_number: e.target.value })}
                        required
                        className="rounded-xl border-orange-100 focus:ring-orange-200"
                    />
                </div>
            </div>

            <div className="flex flex-col sm:flex-row gap-3">
                <Button type="submit" disabled={loading || deleting} className="w-full sm:w-auto bg-[#FF6F00] hover:bg-orange-700 rounded-xl px-8 shadow-lg shadow-orange-200">
                    {loading && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                    Save Changes
                </Button>
                <Button
                    type="button"
                    variant="destructive"
                    disabled={loading || deleting}
                    onClick={() => setShowDeleteDialog(true)}
                    className="w-full sm:w-auto"
                >
                    {deleting && <Loader2 className="mr-2 h-4 w-4 animate-spin" />}
                    Delete Account
                </Button>
            </div>

            <ActionConfirmationDialog
                open={showDeleteDialog}
                onOpenChange={setShowDeleteDialog}
                onConfirm={handleDeleteAccount}
                title="Delete Account?"
                description="Are you sure you want to delete your account from PanditYatra? This action cannot be undone."
                confirmLabel="Yes, Delete"
                isLoading={deleting}
            />
        </form>
    );
};

