import { useState, useEffect } from 'react';
import { DateTime } from 'luxon';

export interface LocationData {
    latitude: number | null;
    longitude: number | null;
    timezone: string;
    isNepalTime: boolean;
    error: string | null;
    country: string | null;
    city: string | null;
    currency: 'NPR' | 'USD' | 'AUD';
    recommendedPaymentGateway: 'KHALTI' | 'STRIPE';
}

export const useLocation = () => {
    const [location, setLocation] = useState<LocationData>({
        latitude: null,
        longitude: null,
        timezone: DateTime.local().zoneName,
        isNepalTime: DateTime.local().zoneName === 'Asia/Kathmandu',
        error: null,
        country: null,
        city: null,
        currency: 'USD',
        recommendedPaymentGateway: 'STRIPE',
    });

    useEffect(() => {
        detectLocationAndTimezone();
    }, []);

    const detectLocationAndTimezone = async () => {
        // First, get browser timezone
        const browserTimezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
        const isNepal = browserTimezone === 'Asia/Kathmandu';

        setLocation(prev => ({
            ...prev,
            timezone: browserTimezone,
            isNepalTime: isNepal,
            currency: isNepal ? 'NPR' : 'USD',
            recommendedPaymentGateway: isNepal ? 'KHALTI' : 'STRIPE'
        }));

        // Then try to get precise geolocation
        if (!navigator.geolocation) {
            setLocation(prev => ({ ...prev, error: 'Geolocation is not supported by your browser' }));
            return;
        }

        navigator.geolocation.getCurrentPosition(
            async (position) => {
                const { latitude, longitude } = position.coords;

                try {
                    // Reverse geocoding to get country/city
                    const locationData = await reverseGeocode(latitude, longitude);

                    setLocation(prev => ({
                        ...prev,
                        latitude,
                        longitude,
                        country: locationData.country,
                        city: locationData.city,
                        currency: getCurrencyFromCountry(locationData.country),
                        recommendedPaymentGateway: getPaymentGatewayFromCountry(locationData.country),
                        error: null,
                    }));
                } catch (err) {
                    // Fallback to just coordinates
                    setLocation(prev => ({
                        ...prev,
                        latitude,
                        longitude,
                        error: null,
                    }));
                }
            },
            (error) => {
                setLocation(prev => ({ ...prev, error: error.message }));
            },
            {
                enableHighAccuracy: true,
                timeout: 10000,
                maximumAge: 300000 // 5 minutes cache
            }
        );
    };

    const reverseGeocode = async (lat: number, lng: number) => {
        // Using a free geocoding service (you can replace with your preferred service)
        try {
            const response = await fetch(
                `https://api.bigdatacloud.net/data/reverse-geocode-client?latitude=${lat}&longitude=${lng}&localityLanguage=en`
            );
            const data = await response.json();
            return {
                country: data.countryName || null,
                city: data.city || data.locality || null,
            };
        } catch (error) {
            console.warn('Reverse geocoding failed:', error);
            return { country: null, city: null };
        }
    };

    const getCurrencyFromCountry = (country: string | null): 'NPR' | 'USD' | 'AUD' => {
        if (!country) return 'USD';

        const countryLower = country.toLowerCase();
        if (countryLower.includes('nepal')) return 'NPR';
        if (countryLower.includes('australia')) return 'AUD';
        return 'USD';
    };

    const getPaymentGatewayFromCountry = (country: string | null): 'KHALTI' | 'STRIPE' => {
        if (!country) return 'STRIPE';

        const countryLower = country.toLowerCase();
        if (countryLower.includes('nepal')) return 'KHALTI';
        return 'STRIPE';
    };

    /**
     * Converts any ISO date string or DateTime object to Nepal Time (Asia/Kathmandu)
     */
    const toNepalTime = (date: string | Date | DateTime) => {
        let dt: DateTime;
        if (typeof date === 'string') {
            dt = DateTime.fromISO(date);
        } else if (date instanceof Date) {
            dt = DateTime.fromJSDate(date);
        } else {
            dt = date;
        }
        return dt.setZone('Asia/Kathmandu');
    };

    /**
     * Formats a date for display, showing both local and Nepal time if they differ
     */
    const formatWithNepalTime = (date: string | Date | DateTime) => {
        const localDt = typeof date === 'string' ? DateTime.fromISO(date) : (date instanceof Date ? DateTime.fromJSDate(date) : date);
        const nepalDt = toNepalTime(date);

        const localStr = localDt.toFormat('ff');
        const nepalStr = nepalDt.toFormat('ff');

        if (location.isNepalTime) {
            return nepalStr;
        }

        return `${localStr} (Nepal: ${nepalStr})`;
    };

    /**
     * Get location context for AI recommendations
     */
    const getLocationContext = () => {
        return {
            timezone: location.timezone,
            country: location.country,
            city: location.city,
            currency: location.currency,
            coordinates: location.latitude && location.longitude ? 
                `${location.latitude},${location.longitude}` : null,
            isNepal: location.isNepalTime,
            recommendedGateway: location.recommendedPaymentGateway
        };
    };

    return {
        ...location,
        toNepalTime,
        formatWithNepalTime,
        getLocationContext,
        detectLocationAndTimezone,
    };
};

import { useState, useEffect, useCallback } from 'react';
import { useAuth } from './useAuth';
import apiClient from '@/lib/api-client';

export interface Notification {
  id: number;
  title: string;
  message: string;
  type: 'booking' | 'payment' | 'puja' | 'system' | 'reminder';
  is_read: boolean;
  created_at: string;
  booking_id?: number;
  action_url?: string;
}

export interface NotificationPermission {
  granted: boolean;
  denied: boolean;
  default: boolean;
}

export const useNotifications = () => {
  const { user, token } = useAuth();
  const [notifications, setNotifications] = useState<Notification[]>([]);
  const [unreadCount, setUnreadCount] = useState(0);
  const [permission, setPermission] = useState<NotificationPermission>({
    granted: false,
    denied: false,
    default: true
  });
  const [loading, setLoading] = useState(false);
  const [authFailed, setAuthFailed] = useState(false);

  // Check browser notification permission on mount
  useEffect(() => {
    if ('Notification' in window) {
      const currentPermission = Notification.permission;
      setPermission({
        granted: currentPermission === 'granted',
        denied: currentPermission === 'denied',
        default: currentPermission === 'default'
      });
    }
  }, []);

  // Fetch notifications when user is authenticated
  useEffect(() => {
    if (user && token && !authFailed) {
      fetchNotifications();
      // Set up periodic refresh
      const interval = setInterval(fetchNotifications, 30000); // Every 30 seconds
      return () => clearInterval(interval);
    }
  }, [user, token, authFailed]);

  useEffect(() => {
    // Reset auth failure flag when token changes (e.g. relogin/refresh)
    setAuthFailed(false);
  }, [token]);

  const fetchNotifications = async () => {
    if (!token) return;

    try {
      setLoading(true);
      const response = await apiClient.get('/notifications/');
      const notificationData = response.data.results || response.data;

      setNotifications(notificationData);
      setUnreadCount(notificationData.filter((n: Notification) => !n.is_read).length);
    } catch (error) {
      const status = (error as any)?.response?.status;
      if (status === 401) {
        setAuthFailed(true);
        return;
      }
      console.error('Failed to fetch notifications:', error);
    } finally {
      setLoading(false);
    }
  };

  const requestPermission = async (): Promise<boolean> => {
    if (!('Notification' in window)) {
      console.warn('This browser does not support notifications');
      return false;
    }

    if (Notification.permission === 'granted') {
      setPermission({ granted: true, denied: false, default: false });
      return true;
    }

    if (Notification.permission === 'denied') {
      setPermission({ granted: false, denied: true, default: false });
      return false;
    }

    try {
      const result = await Notification.requestPermission();
      const granted = result === 'granted';

      setPermission({
        granted,
        denied: result === 'denied',
        default: result === 'default'
      });

      return granted;
    } catch (error) {
      console.error('Error requesting notification permission:', error);
      return false;
    }
  };

  const showBrowserNotification = (notification: Notification) => {
    if (!permission.granted) return;

    const browserNotification = new Notification(notification.title, {
      body: notification.message,
      icon: '/icon-192x192.png', // PWA icon
      badge: '/icon-192x192.png',
      tag: `notification-${notification.id}`,
      requireInteraction: notification.type === 'booking' || notification.type === 'puja'
    });

    browserNotification.onclick = () => {
      window.focus();
      if (notification.action_url) {
        window.location.href = notification.action_url;
      }
      browserNotification.close();
    };

    // Auto-close after 10 seconds for non-critical notifications
    if (notification.type !== 'booking' && notification.type !== 'puja') {
      setTimeout(() => {
        browserNotification.close();
      }, 10000);
    }
  };

  const markAsRead = async (notificationId: number) => {
    try {
      await apiClient.patch(`/notifications/${notificationId}/`, {
        is_read: true
      });

      setNotifications(prev => 
        prev.map(n => 
          n.id === notificationId ? { ...n, is_read: true } : n
        )
      );

      setUnreadCount(prev => Math.max(0, prev - 1));
    } catch (error) {
      console.error('Failed to mark notification as read:', error);
    }
  };

  const markAllAsRead = async () => {
    try {
      await apiClient.post('/notifications/mark-all-read/');

      setNotifications(prev => 
        prev.map(n => ({ ...n, is_read: true }))
      );

      setUnreadCount(0);
    } catch (error) {
      console.error('Failed to mark all notifications as read:', error);
    }
  };

  const deleteNotification = async (notificationId: number) => {
    try {
      await apiClient.delete(`/notifications/${notificationId}/`);

      setNotifications(prev => prev.filter(n => n.id !== notificationId));

      // Update unread count if the deleted notification was unread
      const deletedNotification = notifications.find(n => n.id === notificationId);
      if (deletedNotification && !deletedNotification.is_read) {
        setUnreadCount(prev => Math.max(0, prev - 1));
      }
    } catch (error) {
      console.error('Failed to delete notification:', error);
    }
  };

  // Simulate real-time notifications (in production, use WebSocket)
  const simulateRealTimeNotification = useCallback((notification: Notification) => {
    setNotifications(prev => [notification, ...prev]);
    setUnreadCount(prev => prev + 1);

    // Show browser notification if permission granted
    if (permission.granted) {
      showBrowserNotification(notification);
    }
  }, [permission.granted]);

  // WebSocket connection for real-time notifications (placeholder)
  useEffect(() => {
    if (!user || !token) return;

    // In a real implementation, you would connect to a WebSocket here
    // For now, we'll use polling as implemented above

    // Example WebSocket setup:
    // const ws = new WebSocket(`ws://localhost:8000/ws/notifications/${user.id}/`);
    // ws.onmessage = (event) => {
    //   const notification = JSON.parse(event.data);
    //   simulateRealTimeNotification(notification);
    // };
    // return () => ws.close();
  }, [user, token, simulateRealTimeNotification]);

  const getNotificationIcon = (type: string) => {
    switch (type) {
      case 'booking':
        return '📅';
      case 'payment':
        return '💳';
      case 'puja':
        return '🕉️';
      case 'reminder':
        return '⏰';
      case 'system':
        return '🔔';
      default:
        return '📢';
    }
  };

  const getNotificationColor = (type: string) => {
    switch (type) {
      case 'booking':
        return 'blue';
      case 'payment':
        return 'green';
      case 'puja':
        return 'orange';
      case 'reminder':
        return 'yellow';
      case 'system':
        return 'gray';
      default:
        return 'blue';
    }
  };

  return {
    notifications,
    unreadCount,
    permission,
    loading,
    fetchNotifications,
    requestPermission,
    markAsRead,
    markAllAsRead,
    deleteNotification,
    simulateRealTimeNotification,
    getNotificationIcon,
    getNotificationColor
  };
};

import { useState, useEffect } from 'react';

export const usePWA = () => {
    const [deferredPrompt, setDeferredPrompt] = useState<any>(null);
    const [isInstallable, setIsInstallable] = useState(false);

    useEffect(() => {
        const handler = (e: any) => {
            // Prevent Chrome 67 and earlier from automatically showing the prompt
            e.preventDefault();
            // Stash the event so it can be triggered later.
            setDeferredPrompt(e);
            setIsInstallable(true);
        };

        window.addEventListener('beforeinstallprompt', handler);

        window.addEventListener('appinstalled', () => {
            setIsInstallable(false);
            setDeferredPrompt(null);
            console.log('PWA was installed');
        });

        return () => window.removeEventListener('beforeinstallprompt', handler);
    }, []);

    const installPWA = async () => {
        if (!deferredPrompt) return;

        deferredPrompt.prompt();
        const { outcome } = await deferredPrompt.userChoice;

        if (outcome === 'accepted') {
            console.log('User accepted the install prompt');
        } else {
            console.log('User dismissed the install prompt');
        }

        setDeferredPrompt(null);
        setIsInstallable(false);
    };

    return { isInstallable, installPWA };
};

import axios from 'axios';
import { API_BASE_URL } from './helper';

// Create Axios instance
const apiClient = axios.create({
    baseURL: API_BASE_URL,
    // headers: {
    //     'Content-Type': 'application/json',
    // },
});

// Request Interceptor: Attach Token
apiClient.interceptors.request.use(
    (config) => {
        const token = localStorage.getItem('token');
        if (token) {
            config.headers.Authorization = `Bearer ${token}`;
        }

        // If data is FormData, let browser set Content-Type
        if (config.data instanceof FormData) {
            delete config.headers['Content-Type'];
        }

        return config;
    },
    (error) => Promise.reject(error)
);

// Response Interceptor: Handle Token Refresh
let isRefreshing = false;
let failedQueue: any[] = [];

const processQueue = (error: any, token: string | null = null) => {
    failedQueue.forEach((prom) => {
        if (error) {
            prom.reject(error);
        } else {
            prom.resolve(token);
        }
    });
    failedQueue = [];
};

apiClient.interceptors.response.use(
    (response) => response,
    async (error) => {
        const originalRequest = error.config;

        // Check for 401 Unauthorized and ensure we haven't already tried to refresh
        if (error.response?.status === 401 && !originalRequest._retry) {
            if (isRefreshing) {
                return new Promise(function (resolve, reject) {
                    failedQueue.push({ resolve, reject });
                })
                    .then((token) => {
                        originalRequest.headers.Authorization = `Bearer ${token}`;
                        return apiClient(originalRequest);
                    })
                    .catch((err) => Promise.reject(err));
            }

            originalRequest._retry = true;
            isRefreshing = true;

            const refreshToken = localStorage.getItem('refresh'); // Assuming you store refresh token

            if (!refreshToken) {
                // No refresh token, force logout
                handleLogout();
                return Promise.reject(error);
            }

            try {
                const response = await axios.post(`${API_BASE_URL}/token/refresh/`, {
                    refresh: refreshToken,
                });

                const { access } = response.data;

                localStorage.setItem('token', access);

                apiClient.defaults.headers.common['Authorization'] = `Bearer ${access}`;
                processQueue(null, access);

                return apiClient(originalRequest);
            } catch (err) {
                processQueue(err, null);
                handleLogout();
                return Promise.reject(err);
            } finally {
                isRefreshing = false;
            }
        }

        return Promise.reject(error);
    }
);

function handleLogout() {
    localStorage.removeItem('token');
    localStorage.removeItem('refresh');
    localStorage.removeItem('role');
    localStorage.removeItem('user');
    window.location.href = '/login'; // Redirect to login
}

