import React, { useState } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Textarea } from '@/components/ui/textarea';
import { Label } from '@/components/ui/label';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Star, Loader2, ArrowLeft } from 'lucide-react';
import apiClient from '@/lib/api-client';
import { motion } from 'framer-motion';


const ReviewForm = () => {
    const { id } = useParams<{ id: string }>();
    const navigate = useNavigate();
    const [rating, setRating] = useState(0);
    const [hoverRating, setHoverRating] = useState(0);
    const [comment, setComment] = useState('');
    const [loading, setLoading] = useState(false);
    const [error, setError] = useState<string | null>(null);
    const [alreadyReviewed, setAlreadyReviewed] = useState(false);

    React.useEffect(() => {
        // Check if review already exists for this booking
        if (!id) return;
        apiClient.get(`/reviews/booking/${id}/`).then(res => {
            if (res.data && res.data.id) {
                setAlreadyReviewed(true);
            }
        }).catch(() => {
            // If 404, no review exists; otherwise, ignore
        });
    }, [id]);

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        if (alreadyReviewed) {
            setError("You have already submitted a review for this booking.");
            return;
        }
        if (rating === 0) {
            setError("Please select a star rating.");
            return;
        }

        setLoading(true);
        setError(null);

        try {
            await apiClient.post('/reviews/create/', {
                booking: id,
                rating,
                comment
            });
            // Success!
            navigate('/my-bookings');
        } catch (err: any) {
            console.error(err);
            const msg = err.response?.data?.detail || "Failed to submit review.";
            setError(msg);
            if (msg && msg.toLowerCase().includes('already reviewed')) {
                setAlreadyReviewed(true);
            }
        } finally {
            setLoading(false);
        }
    };

    return (
        <div className="min-h-screen bg-background flex items-center justify-center p-4">
            <motion.div
                initial={{ opacity: 0, scale: 0.95 }}
                animate={{ opacity: 1, scale: 1 }}
                className="max-w-md w-full"
            >
                <Button
                    variant="ghost"
                    className="mb-4 pl-0 hover:bg-transparent text-gray-600 hover:text-orange-600 gap-2"
                    onClick={() => navigate(-1)}
                >
                    <ArrowLeft size={18} />
                    Back
                </Button>

                <Card>
                    <CardHeader className="text-center">
                        <CardTitle className="text-2xl">Rate your Experience</CardTitle>
                        <CardDescription>How was your puja service?</CardDescription>
                    </CardHeader>
                    <CardContent>
                        {alreadyReviewed ? (
                            <Alert variant="destructive" className="mb-6">
                                <AlertDescription>You have already submitted a review for this booking.</AlertDescription>
                            </Alert>
                        ) : error && (
                            <Alert variant="destructive" className="mb-6">
                                <AlertDescription>{error}</AlertDescription>
                            </Alert>
                        )}

                        {!alreadyReviewed && (
                            <form onSubmit={handleSubmit} className="space-y-6">
                                {/* Star Rating */}
                                <div className="flex justify-center flex-col items-center gap-2">
                                    <div className="flex gap-1">
                                        {[1, 2, 3, 4, 5].map((star) => (
                                            <button
                                                key={star}
                                                type="button"
                                                className="transition-transform hover:scale-110 focus:outline-none"
                                                onMouseEnter={() => setHoverRating(star)}
                                                onMouseLeave={() => setHoverRating(0)}
                                                onClick={() => setRating(star)}
                                            >
                                                <Star
                                                    size={32}
                                                    className={`${star <= (hoverRating || rating)
                                                        ? "fill-yellow-400 text-yellow-400"
                                                        : "text-gray-300"
                                                        } transition-colors`}
                                                />
                                            </button>
                                        ))}
                                    </div>
                                    <p className="text-sm font-medium text-gray-500">
                                        {rating > 0 ? `${rating} Stars` : "Select a rating"}
                                    </p>
                                </div>

                                <div className="space-y-2">
                                    <Label htmlFor="comment">Your Review</Label>
                                    <Textarea
                                        id="comment"
                                        placeholder="Share your experience with the pandit..."
                                        className="min-h-[120px]"
                                        value={comment}
                                        onChange={(e) => setComment(e.target.value)}
                                        required
                                    />
                                </div>

                                <Button
                                    type="submit"
                                    className="w-full bg-orange-600 hover:bg-orange-700"
                                    disabled={loading}
                                >
                                    {loading ? <Loader2 className="animate-spin mr-2 h-4 w-4" /> : null}
                                    Submit Review
                                </Button>
                            </form>
                        )}
                    </CardContent>
                </Card>
            </motion.div>
        </div>
    );
};

export default ReviewForm;

import React, { useState, useEffect } from 'react';
import Navbar from '@/components/layout/Navbar';
import Footer from '@/components/layout/Footer';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import {
    ChevronLeft,
    ChevronRight,
    Sun,
    Moon,
    Sparkles,
    Calendar as CalendarIcon,
    AlertCircle,
    CalendarDays
} from 'lucide-react';
import { fetchPanchang } from '@/services/api';
import {
    format,
    addMonths,
    subMonths,
    startOfMonth,
    endOfMonth,
    eachDayOfInterval,
    getDay,
    isSameDay,
    isToday
} from 'date-fns';

const NepaliMonthNames = ["Baishakh", "Jestha", "Ashadh", "Shrawan", "Bhadra", "Ashwin", "Kartik", "Mangsir", "Poush", "Magh", "Falgun", "Chaitra"];

const PanchangCalendar: React.FC = () => {
    const [currentMonth, setCurrentMonth] = useState(new Date());
    const [panchangData, setPanchangData] = useState<any[]>([]);
    const [loading, setLoading] = useState(true);
    const [selectedDate, setSelectedDate] = useState<any>(null);

    const monthStart = startOfMonth(currentMonth);
    const monthEnd = endOfMonth(currentMonth);
    const daysInMonth = eachDayOfInterval({ start: monthStart, end: monthEnd });
    const startDay = getDay(monthStart);

    useEffect(() => {
        const loadPanchang = async () => {
            setLoading(true);
            try {
                const data = await fetchPanchang(format(monthStart, 'yyyy-MM-dd'), 31);
                setPanchangData(data || []);

                const today = new Date();
                const initialSelected = isSameDay(today, currentMonth) ? today : monthStart;
                const found = data?.find((d: any) => isSameDay(new Date(d.date), initialSelected));
                setSelectedDate(found || null);
            } catch (err) {
                console.error('Failed to load month panchang:', err);
            } finally {
                setLoading(false);
            }
        };
        loadPanchang();
    }, [currentMonth]);

    const nextMonth = () => setCurrentMonth(addMonths(currentMonth, 1));
    const prevMonth = () => setCurrentMonth(subMonths(currentMonth, 1));
    const setMonth = (monthIdx: string) => {
        const newDate = new Date(currentMonth.getFullYear(), parseInt(monthIdx), 1);
        setCurrentMonth(newDate);
    };
    const setYear = (year: string) => {
        const newDate = new Date(parseInt(year), currentMonth.getMonth(), 1);
        setCurrentMonth(newDate);
    };

    const getDayPanchang = (date: Date) => {
        return panchangData.find(d => isSameDay(new Date(d.date), date));
    };

    const toNepaliNumeral = (num: number | string | undefined | null) => {
        if (!num) return '';
        const numerals: any = {
            '0': '०', '1': '१', '2': '२', '3': '३', '4': '४', '5': '५', '6': '६', '7': '७', '8': '८', '9': '९'
        };
        return num.toString().split('').map(char => numerals[char] || char).join('');
    };

    const renderHeader = () => {
        const years = Array.from({ length: 10 }, (_, i) => 2024 + i);
        const months = [
            "January", "February", "March", "April", "May", "June",
            "July", "August", "September", "October", "November", "December"
        ];

        return (
            <div className="flex flex-col md:flex-row md:items-center justify-between mb-10 gap-6">
                <div className="space-y-1">
                    <div className="flex items-center gap-3">
                        <div className="bg-orange-600 p-2 rounded-xl text-white">
                            <CalendarDays className="w-6 h-6" />
                        </div>
                        <h1 className="text-4xl font-black text-[#3E2723] tracking-tight">Nepali Patro</h1>
                    </div>
                    <p className="text-orange-600 font-bold uppercase tracking-[0.2em] text-[10px] ml-11">
                        Spiritual Calendar & Guidance
                    </p>
                </div>

                <div className="flex items-center gap-3 bg-white p-2 rounded-2xl border border-orange-100 shadow-sm">
                    <Select value={currentMonth.getMonth().toString()} onValueChange={setMonth}>
                        <SelectTrigger className="w-[140px] border-none bg-orange-50/50 hover:bg-orange-50 font-bold text-orange-800 rounded-xl focus:ring-0">
                            <SelectValue placeholder="Month" />
                        </SelectTrigger>
                        <SelectContent className="rounded-xl border-orange-100 shadow-xl">
                            {months.map((m, i) => (
                                <SelectItem key={m} value={i.toString()} className="font-medium text-[#3E2723] focus:bg-orange-50 focus:text-orange-700">
                                    {m}
                                </SelectItem>
                            ))}
                        </SelectContent>
                    </Select>

                    <Select value={currentMonth.getFullYear().toString()} onValueChange={setYear}>
                        <SelectTrigger className="w-[100px] border-none bg-orange-50/50 hover:bg-orange-50 font-bold text-orange-800 rounded-xl focus:ring-0">
                            <SelectValue placeholder="Year" />
                        </SelectTrigger>
                        <SelectContent className="rounded-xl border-orange-100 shadow-xl">
                            {years.map(y => (
                                <SelectItem key={y} value={y.toString()} className="font-medium text-[#3E2723] focus:bg-orange-50 focus:text-orange-700">
                                    {y}
                                </SelectItem>
                            ))}
                        </SelectContent>
                    </Select>

                    <div className="h-8 w-px bg-orange-100 mx-1" />

                    <div className="flex gap-1">
                        <Button variant="ghost" size="icon" onClick={prevMonth} className="rounded-xl hover:bg-orange-100 text-orange-600">
                            <ChevronLeft className="w-5 h-5" />
                        </Button>
                        <Button variant="ghost" size="icon" onClick={nextMonth} className="rounded-xl hover:bg-orange-100 text-orange-600">
                            <ChevronRight className="w-5 h-5" />
                        </Button>
                    </div>
                </div>
            </div>
        );
    };

    const renderDays = () => {
        const days = ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'];
        return (
            <div className="grid grid-cols-7 mb-6 gap-2">
                {days.map(day => (
                    <div key={day} className="text-center">
                        <div className="bg-orange-600 text-white rounded-xl py-2 px-1 text-[10px] font-black uppercase tracking-wider shadow-sm shadow-orange-200">
                            {day}
                        </div>
                    </div>
                ))}
            </div>
        );
    };

    const renderCells = () => {
        const cells = [];
        for (let i = 0; i < startDay; i++) {
            cells.push(<div key={`empty-${i}`} className="aspect-square opacity-0" />);
        }

        daysInMonth.forEach(day => {
            const data = getDayPanchang(day);
            const isTodayDate = isToday(day);
            const isSelected = selectedDate && isSameDay(new Date(selectedDate.date), day);
            const hasFestival = data?.festivals?.length > 0;

            cells.push(
                <div
                    key={day.toString()}
                    onClick={() => setSelectedDate(data)}
                    className={`
                        relative aspect-square border-t border-l border-orange-100 cursor-pointer transition-all duration-300
                        hover:bg-orange-50/80 flex flex-col p-2 group rounded-xl
                        ${isTodayDate ? 'bg-orange-50 ring-2 ring-inset ring-orange-200 z-10' : 'bg-white'}
                        ${isSelected ? 'bg-[#FF6F00] border-none shadow-2xl scale-105 z-20' : ''}
                        ${hasFestival ? 'bg-red-50/40' : ''}
                    `}
                >
                    <div className="flex justify-between items-start">
                        <div className="flex flex-col">
                            <span className={`text-xl font-black leading-none ${isSelected ? 'text-white' : 'text-[#3E2723]'}`}>
                                {data ? toNepaliNumeral(data.bs_day) : ''}
                            </span>
                            <span className={`text-[9px] font-bold mt-1 ${isSelected ? 'text-orange-100' : 'text-orange-600/60'}`}>
                                {data ? data.bs_day : ''}
                            </span>
                        </div>
                        <div className={`text-[10px] font-bold px-1.5 py-0.5 rounded-full ${isSelected ? 'bg-white/20 text-white' : 'bg-gray-100 text-gray-500'}`}>
                            {format(day, 'd')}
                        </div>
                    </div>

                    {data && (
                        <div className="mt-auto space-y-1">
                            {hasFestival && (
                                <div className="flex items-center gap-1">
                                    <Sparkles className={`w-2.5 h-2.5 ${isSelected ? 'text-yellow-300' : 'text-red-500'}`} />
                                    <div className={`text-[7px] font-bold truncate ${isSelected ? 'text-white' : 'text-red-600'}`}>
                                        {data.festivals[0]}
                                    </div>
                                </div>
                            )}
                            <div className={`text-[8px] font-bold px-1 py-0.5 rounded bg-black/5 inline-block ${isSelected ? 'text-white bg-white/10' : 'text-[#3E2723]/60'}`}>
                                {data.tithi}
                            </div>
                        </div>
                    )}
                </div>
            );
        });

        const totalCells = Math.ceil((startDay + daysInMonth.length) / 7) * 7;
        for (let i = cells.length; i < totalCells; i++) {
            cells.push(<div key={`empty-end-${i}`} className="aspect-square opacity-20 bg-gray-50/30 rounded-xl" />);
        }

        return cells;
    };

    return (
        <div className="min-h-screen bg-[#FDFBF9] flex flex-col">
            <Navbar />

            <main className="flex-grow container mx-auto px-4 py-20 lg:py-24 max-w-6xl">
                <div className="grid lg:grid-cols-3 gap-12">
                    <div className="lg:col-span-2 order-2 lg:order-1">
                        {renderHeader()}
                        {renderDays()}
                        <div className="gap-2 grid grid-cols-7 bg-white/50 p-2 rounded-3xl border border-orange-100 shadow-inner">
                            {renderCells()}
                        </div>

                        <div className="mt-8 flex items-center gap-6 justify-center text-xs font-bold text-orange-800/60 uppercase tracking-widest">
                            <div className="flex items-center gap-2">
                                <span className="w-3 h-3 rounded-full bg-[#FF6F00]" /> Selected Date
                            </div>
