                )}

                {/* Pagination Controls */}
                {sortedItems.length > itemsPerPage && (
                    <div className="flex justify-center mt-12 gap-2">
                        <Button variant="outline" size="icon" onClick={() => setCurrentPage(p => Math.max(1, p - 1))} disabled={currentPage === 1}>
