                            {/* Product Details */}
                            <div className="md:w-1/2 p-8 flex flex-col">
                                <div className="flex justify-between items-start mb-4">
                                    <div>
                                        <Badge className="bg-orange-100 text-orange-600 hover:bg-orange-100 border-none mb-2">
