                                            <p className="text-xs text-gray-400 text-center italic">
                                                ≈ ${(totalPayable * 0.0075).toFixed(2)} USD
                                            </p>
                                        )}
                                    </div>

                                    {/* Security Badges */}
                                    <div className="mt-6 pt-6 border-t border-orange-100 flex justify-center gap-6">
