                                            <span>SSL Encrypted</span>
                                        </div>
                                        <div className="flex items-center gap-2 text-xs text-gray-500">
                                            <Truck className="w-4 h-4 text-orange-500" />
                                            <span>Free Delivery</span>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>

                        {/* Right Side - Form */}
