    // Navigate to booking form for this puja
    navigate(`/booking?pujaId=${puja.id}`);
  };

  const handleAddToCart = (puja: Puja | null) => {
    if (!puja) return;

    addItem({
      id: `puja-${puja.id}`,
      title: puja.name || 'Puja Service',
      price: puja.price,
      meta: {
        type: 'puja',
        panditId: puja.pandit,
        duration: puja.duration_minutes
      }
    }, 1);

    toast({
      title: "✅ Added to Cart",
      description: `${puja.name || 'Puja service'} has been added to your cart.`,
      className: "bg-green-600 text-white border-none shadow-2xl"
    });
  };

  useEffect(() => {
    loadData();
  }, []);

  const loadData = async () => {
    try {
      setLoading(true);
      const data = await fetchPujas();
      // Map API response (base_price/base_duration) to component structure (price/duration_minutes)
      const mappedData = (Array.isArray(data) ? data : []).map((item: any) => ({
        ...item,
        price: item.base_price ? Number(item.base_price) : 0,
        duration_minutes: item.base_duration_minutes || 60,
        pandit_name: "PanditYatra Verified", // Default for catalog items
        pandit: 0
      }));
      setPujas(mappedData);
    } catch (error) {
      console.error('Failed to load pujas:', error);
      toast({
        title: "Error",
        description: "Failed to load services.",
        variant: "destructive"
      });
    } finally {
      setLoading(false);
    }
