              <Flame className="w-4 h-4 mr-2" />
              Divine Services
            </Badge>
            <h1 className="text-4xl md:text-5xl font-bold mb-6 font-playfair">
              Online Puja Services
            </h1>
            <p className="text-orange-100 text-lg mb-8 leading-relaxed">
