import React, { useState, useEffect } from 'react';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from '@/components/ui/table';
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from '@/components/ui/select';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Badge } from '@/components/ui/badge';
import { useToast } from '@/hooks/use-toast';
import { fetchBookings, adminCancelBooking, type Booking } from '@/lib/api';
import { Loader2, Search, Ban, CreditCard, RefreshCcw } from 'lucide-react';

const AdminBookings = () => {
    const [bookings, setBookings] = useState<Booking[]>([]);
    const [loading, setLoading] = useState(true);
    const [searchTerm, setSearchTerm] = useState('');
    const [statusFilter, setStatusFilter] = useState<string>('all');
    const [dateFilter, setDateFilter] = useState('');
    const { toast } = useToast();

    useEffect(() => {
        loadBookings();
    }, []);

    const loadBookings = async () => {
        setLoading(true);
        try {
            const data = await fetchBookings();
            setBookings(data);
        } catch (error) {
            console.error('Failed to load bookings:', error);
            toast({
                title: 'Error',
                description: 'Failed to load bookings',
                variant: 'destructive',
            });
        } finally {
            setLoading(false);
        }
    };

    const handleCancelAndRefund = async (bookingId: number) => {
        if (!confirm('Are you sure you want to cancel this booking and initiate a refund?')) return;

        try {
            await adminCancelBooking(bookingId);
            toast({
                title: 'Success',
                description: 'Booking cancelled and refund process initiated.',
            });
            loadBookings(); // Refresh list
        } catch (error) {
            console.error('Cancel failed:', error);
            toast({
                title: 'Error',
                description: 'Failed to cancel booking',
                variant: 'destructive',
            });
        }
    };

    const filteredBookings = bookings.filter((booking) => {
        const matchesSearch =
            (booking.pandit_full_name || '').toLowerCase().includes(searchTerm.toLowerCase()) ||
            (booking.user_full_name || '').toLowerCase().includes(searchTerm.toLowerCase());

        const matchesStatus = statusFilter === 'all' || booking.status === statusFilter;

        const matchesDate = dateFilter ? booking.booking_date === dateFilter : true;

        return matchesSearch && matchesStatus && matchesDate;
    });

    const getStatusBadge = (status: string) => {
        let className = "";
        let variant: "default" | "destructive" | "outline" | "secondary" = "outline";

        switch (status) {
            case 'COMPLETED':
                className = "bg-green-500 hover:bg-green-600 border-transparent text-primary-foreground";
                variant = "default";
                break;
            case 'ACCEPTED':
                className = "bg-blue-500 hover:bg-blue-600 border-transparent text-primary-foreground";
                variant = "default";
                break;
            case 'PENDING':
                className = "bg-yellow-500 hover:bg-yellow-600 border-transparent text-primary-foreground";
                variant = "secondary";
                break;
            case 'CANCELLED':
                variant = "destructive";
                break;
            default:
                variant = "outline";
        }

        return <Badge className={className} variant={variant}>{status}</Badge>;
    };

    return (
        <DashboardLayout userRole="admin">
            <div className="space-y-6">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                    <h1 className="text-3xl font-bold">Manage Bookings</h1>
                    <Button variant="outline" onClick={loadBookings}>
                        <RefreshCcw className="mr-2 h-4 w-4" /> Refresh
                    </Button>
                </div>

                <Card>
                    <CardHeader>
                        <CardTitle>Bookings Overview</CardTitle>
                    </CardHeader>
                    <CardContent>
                        {/* Filters */}
                        <div className="flex flex-col md:flex-row gap-4 mb-6">
                            <div className="relative flex-1">
                                <Search className="absolute left-2.5 top-2.5 h-4 w-4 text-muted-foreground" />
                                <Input
                                    placeholder="Search by Pandit or Customer..."
                                    className="pl-8"
                                    value={searchTerm}
                                    onChange={(e) => setSearchTerm(e.target.value)}
                                />
                            </div>
                            <Select value={statusFilter} onValueChange={setStatusFilter}>
                                <SelectTrigger className="w-[180px]">
                                    <SelectValue placeholder="Status" />
                                </SelectTrigger>
                                <SelectContent>
                                    <SelectItem value="all">All Status</SelectItem>
                                    <SelectItem value="PENDING">Pending</SelectItem>
                                    <SelectItem value="ACCEPTED">Accepted</SelectItem>
                                    <SelectItem value="COMPLETED">Completed</SelectItem>
                                    <SelectItem value="CANCELLED">Cancelled</SelectItem>
                                </SelectContent>
                            </Select>
                            <Input
                                type="date"
                                className="w-[180px]"
                                value={dateFilter}
                                onChange={(e) => setDateFilter(e.target.value)}
                            />
                            {(searchTerm || statusFilter !== 'all' || dateFilter) && (
                                <Button 
                                    variant="ghost" 
                                    onClick={() => {
                                        setSearchTerm('');
                                        setStatusFilter('all');
                                        setDateFilter('');
                                    }}
                                >
                                    Clear Filters
                                </Button>
                            )}
                        </div>

                        {/* Table */}
                        <div className="rounded-md border">
                            <Table>
                                <TableHeader>
                                    <TableRow>
                                        <TableHead>ID</TableHead>
                                        <TableHead>Customer</TableHead>
                                        <TableHead>Pandit</TableHead>
                                        <TableHead>Date & Time</TableHead>
                                        <TableHead>Amount</TableHead>
                                        <TableHead>Payment</TableHead>
                                        <TableHead>Status</TableHead>
                                        <TableHead className="text-right">Actions</TableHead>
                                    </TableRow>
                                </TableHeader>
                                <TableBody>
                                    {loading ? (
                                        <TableRow>
                                            <TableCell colSpan={8} className="h-24 text-center">
                                                <Loader2 className="mr-2 h-6 w-6 animate-spin inline" />
                                                Loading...
                                            </TableCell>
                                        </TableRow>
                                    ) : filteredBookings.length === 0 ? (
                                        <TableRow>
                                            <TableCell colSpan={8} className="h-24 text-center text-muted-foreground">
                                                No bookings found.
                                            </TableCell>
                                        </TableRow>
                                    ) : (
                                        filteredBookings.map((booking) => (
                                            <TableRow key={booking.id}>
                                                <TableCell className="font-medium">#{booking.id}</TableCell>
                                                <TableCell>{booking.user_full_name}</TableCell>
                                                <TableCell>{booking.pandit_full_name}</TableCell>
                                                <TableCell>
                                                    <div className="flex flex-col">
                                                        <span>{booking.booking_date}</span>
                                                        <span className="text-xs text-muted-foreground">{booking.booking_time}</span>
                                                    </div>
                                                </TableCell>
                                                <TableCell>₹{booking.total_fee}</TableCell>
                                                <TableCell>
                                                    <div className="flex items-center gap-2">
                                                        {booking.payment_method ? (
                                                            <>
                                                                <CreditCard className="h-3 w-3" />
                                                                <span className="capitalize">{booking.payment_method}</span>
                                                            </>
                                                        ) : (
                                                            <span className="text-muted-foreground text-xs">Unpaid</span>
                                                        )}
                                                        {booking.payment_status && (
                                                            <Badge variant="outline" className="text-xs bg-green-50 text-green-700 border-green-200">Paid</Badge>
                                                        )}
                                                    </div>
                                                </TableCell>
                                                <TableCell>{getStatusBadge(booking.status)}</TableCell>
                                                <TableCell className="text-right">
                                                    {booking.status !== 'CANCELLED' && booking.status !== 'COMPLETED' && (
                                                        <Button
                                                            variant="destructive"
                                                            size="sm"
                                                            onClick={() => handleCancelAndRefund(booking.id)}
                                                        >
                                                            <Ban className="mr-2 h-3 w-3" />
                                                            Cancel & Refund
                                                        </Button>
                                                    )}
                                                    {booking.status === 'CANCELLED' && (
                                                        <span className="text-xs text-muted-foreground">Refunded via Gateway</span>
                                                    )}
                                                </TableCell>
                                            </TableRow>
                                        ))
                                    )}
                                </TableBody>
                            </Table>
                        </div>
                    </CardContent>
                </Card>
            </div>
        </DashboardLayout>
    );
};

export default AdminBookings;

import React, { useEffect, useState } from "react";
import apiClient from "@/lib/api-client";
import { Card, CardHeader, CardTitle, CardContent } from "@/components/ui/card";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Loader2, CheckCircle, XCircle } from "lucide-react";

const AdminErrorLogs: React.FC = () => {
  const [logs, setLogs] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [updating, setUpdating] = useState<number | null>(null);

  const fetchLogs = async () => {
    setLoading(true);
    try {
      const res = await apiClient.get("/adminpanel/error-logs/");
      setLogs(res.data);
    } catch (err: any) {
      setError("Failed to load error logs");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchLogs();
  }, []);

  const markResolved = async (id: number) => {
    setUpdating(id);
    try {
      await apiClient.post("/adminpanel/error-logs/", { id, resolved: true });
      fetchLogs();
    } catch {
      setError("Failed to update log");
    } finally {
      setUpdating(null);
    }
  };

  return (
    <Card className="max-w-4xl mx-auto mt-8">
      <CardHeader>
        <CardTitle>Payment & Booking Error Logs</CardTitle>
      </CardHeader>
      <CardContent>
        {loading ? (
          <div className="flex items-center justify-center p-8">
            <Loader2 className="animate-spin mr-2" /> Loading...
          </div>
        ) : error ? (
          <div className="text-red-500">{error}</div>
        ) : logs.length === 0 ? (
          <div className="text-gray-500">No error logs found.</div>
        ) : (
          <div className="space-y-4">
            {logs.map((log) => (
              <div
                key={log.id}
                className="border rounded-lg p-4 flex flex-col md:flex-row md:items-center md:justify-between gap-2 bg-orange-50"
              >
                <div>
                  <div className="flex items-center gap-2 mb-1">
                    <Badge variant={log.resolved ? "default" : "destructive"} className={log.resolved ? "bg-green-100 text-green-800" : ""}>
                      {log.resolved ? "Resolved" : "Unresolved"}
                    </Badge>
                    <span className="text-xs text-gray-400">{new Date(log.created_at).toLocaleString()}</span>
                  </div>
                  <div className="font-semibold text-orange-900">{log.error_type}</div>
                  <div className="text-sm text-gray-800 mb-1">{log.message}</div>
                  {log.context && (
                    <pre className="text-xs bg-gray-100 rounded p-2 overflow-x-auto mb-1">
                      {JSON.stringify(log.context, null, 2)}
                    </pre>
                  )}
                  <div className="text-xs text-gray-500">
                    User: {log.user || "-"} | Booking: {log.booking_id || "-"} | Payment: {log.payment_id || "-"}
                  </div>
                  {log.admin_note && (
                    <div className="text-xs text-blue-700 mt-1">Note: {log.admin_note}</div>
                  )}
                </div>
                <div className="flex flex-col gap-2 min-w-[120px] items-end">
                  {log.resolved ? (
                    <CheckCircle className="text-green-500 w-6 h-6" />
                  ) : (
                    <Button
                      size="sm"
                      variant="outline"
                      disabled={updating === log.id}
                      onClick={() => markResolved(log.id)}
                    >
                      {updating === log.id ? <Loader2 className="animate-spin w-4 h-4 mr-1" /> : <XCircle className="w-4 h-4 mr-1" />}
                      Mark Resolved
                    </Button>
                  )}
                </div>
              </div>
            ))}
          </div>
        )}
      </CardContent>
    </Card>
  );
};

