import React, { useEffect, useState } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { useToast } from "@/hooks/use-toast";
import { fetchAllPujas, type Puja } from "@/lib/api";
import apiClient from "@/lib/api-client";
import { DataTablePagination } from "@/components/common/DataTablePagination";

interface AdminPuja extends Puja {
  is_available: boolean;
}

export default function AdminServices() {
  const [pujas, setPujas] = useState<AdminPuja[]>([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 5;

  const [editingId, setEditingId] = useState<number | null>(null);

  const [form, setForm] = useState<{
    name: string;
    description: string;
    base_duration_minutes: number;
    base_price: string;
    is_available: boolean;
    image: File | null;
  }>({
    name: "",
    description: "",
    base_duration_minutes: 60,
    base_price: "",
    is_available: true,
    image: null,
  });
  const { toast } = useToast();

  const loadPujas = async () => {
    setLoading(true);
    try {
      const data = await fetchAllPujas();
      setPujas(data as AdminPuja[]);
    } catch (err) {
      toast({ title: "Error", description: "Failed to load pujas." });
    }
    setLoading(false);
  };

  useEffect(() => {
    loadPujas();
  }, []);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value, type, checked, files } = e.target;
    setForm((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : type === "file" ? (files ? files[0] : null) : value,
    }));
  };

  const handleEdit = (puja: AdminPuja) => {
    setEditingId(puja.id);
    setForm({
      name: puja.name || "",
      description: puja.description || "",
      base_duration_minutes: puja.base_duration_minutes || 60,
      base_price: puja.base_price ? String(puja.base_price) : "",
      is_available: puja.is_available,
      image: null, // Reset image input on edit as we can't set file input value
    });
    window.scrollTo({ top: 0, behavior: "smooth" });
  };

  const handleCancel = () => {
    setEditingId(null);
    setForm({
      name: "",
      description: "",
      base_duration_minutes: 60,
      base_price: "",
      is_available: true,
      image: null,
    });
  };

  const handleDelete = async (id: number) => {
    if (!confirm("Are you sure you want to delete this puja service?")) return;
    try {
      await apiClient.delete(`/services/${id}/`);
      toast({ title: "Success", description: "Puja deleted successfully." });
      loadPujas();
    } catch (err: any) {
      console.error(err);
      toast({ title: "Error", description: "Failed to delete puja." });
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    const formData = new FormData();
    Object.entries(form).forEach(([key, value]) => {
      // Don't send null image on update unless you want to clear it (logic depends on backend)
      // Usually backend ignores valid key if not present in request. 
      // If image is null here, it means user didn't select a new file.
      if (key === 'image' && value === null) return;

      if (value !== null && value !== "") {
        if ((value as any) instanceof File) {
          formData.append(key, value as File);
        } else {
          formData.append(key, String(value));
        }
      }
    });

    try {
      if (editingId) {
        await apiClient.patch(`/services/${editingId}/`, formData, {
            headers: { "Content-Type": "multipart/form-data" },
        });
        toast({ title: "Success", description: "Puja updated successfully." });
      } else {
        await apiClient.post("/services/", formData, {
            headers: { "Content-Type": "multipart/form-data" },
        });
        toast({ title: "Success", description: "Puja added successfully." });
      }
      handleCancel(); // Reset form
      loadPujas();
    } catch (err: any) {
      console.error(err);
      toast({ title: "Error", description: err.response?.data?.detail || err.message || "Failed to save puja." });
    }
  };

  const totalPages = Math.ceil(pujas.length / itemsPerPage);
  const currentPujas = pujas.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  return (
    <DashboardLayout userRole="admin">
      <Card className="mb-6">
        <CardHeader>
          <CardTitle>{editingId ? "Edit Puja/Service" : "Add New Puja/Service"}</CardTitle>
        </CardHeader>
        <CardContent>
          <form onSubmit={handleSubmit} className="grid grid-cols-1 md:grid-cols-2 gap-4">
            <Input name="name" value={form.name} onChange={handleChange} placeholder="Name" required />
            <Input name="base_price" value={form.base_price} onChange={handleChange} placeholder="Base Price (₹)" required type="number" min="0" />
            <Input name="base_duration_minutes" value={form.base_duration_minutes} onChange={handleChange} placeholder="Duration (min)" required type="number" min="1" />
            <div className="flex flex-col gap-2">
                <Input name="image" type="file" accept="image/*" onChange={handleChange} />
                {editingId && <span className="text-xs text-gray-500">Leave empty to keep existing image</span>}
            </div>
            <Input name="description" value={form.description} onChange={handleChange} placeholder="Description" required />
            <label className="flex items-center gap-2">
              <input type="checkbox" name="is_available" checked={form.is_available} onChange={handleChange} /> Available
            </label>
            <div className="md:col-span-2 flex gap-2">
                <Button type="submit">{editingId ? "Update Puja" : "Add Puja"}</Button>
                {editingId && <Button type="button" variant="outline" onClick={handleCancel}>Cancel</Button>}
            </div>
          </form>
        </CardContent>
      </Card>
      <Card>
        <CardHeader>
          <CardTitle>All Pujas/Services</CardTitle>
        </CardHeader>
        <CardContent>
          {loading ? (
            <div>Loading...</div>
          ) : (
            <>
            <Table>
              <TableHeader>
                <TableRow>
                  <TableHead>Name</TableHead>
                  <TableHead>Description</TableHead>
                  <TableHead>Price (₹)</TableHead>
                  <TableHead>Duration (min)</TableHead>
                  <TableHead>Available</TableHead>
                  <TableHead>Actions</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {currentPujas.map((puja) => (
                  <TableRow key={puja.id}>
                    <TableCell>{puja.name}</TableCell>
                    <TableCell className="max-w-xs truncate">{puja.description}</TableCell>
                    <TableCell>{puja.base_price}</TableCell>
                    <TableCell>{puja.base_duration_minutes}</TableCell>
                    <TableCell>{puja.is_available ? "Yes" : "No"}</TableCell>
                    <TableCell>
                        <div className="flex gap-2">
                            <Button size="sm" variant="outline" onClick={() => handleEdit(puja)}>Edit</Button>
                            <Button size="sm" variant="destructive" onClick={() => handleDelete(puja.id)}>Delete</Button>
                        </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
            <DataTablePagination currentPage={currentPage} totalPages={totalPages} onPageChange={setCurrentPage} />
          </>
          )}
        </CardContent>
      </Card>
    </DashboardLayout>
  );
}

import React, { useEffect, useState } from 'react';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import axiosInstance from '@/lib/api-client';
import { useToast } from "@/hooks/use-toast";

interface PlatformSettings {
    commission_rate: string;
    video_call_rate_per_min: string;
}

const AdminSettings = () => {
    const { toast } = useToast();
    const [settings, setSettings] = useState<PlatformSettings>({
        commission_rate: '',
        video_call_rate_per_min: ''
    });
    const [loading, setLoading] = useState(false);

    useEffect(() => {
        fetchSettings();
    }, []);

    const fetchSettings = async () => {
        try {
            const res = await axiosInstance.get('/users/admin/settings/');
            setSettings(res.data);
        } catch (error) {
            console.error("Failed to fetch settings", error);
        }
    };

    const handleChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        setSettings({ ...settings, [e.target.name]: e.target.value });
    };

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);
        try {
            await axiosInstance.post('/users/admin/settings/', settings);
            toast({
                title: "Settings Updated",
                description: "Platform settings have been saved successfully.",
            });
        } catch (error) {
            toast({
                title: "Error",
                description: "Failed to update settings.",
                variant: "destructive"
            });
        } finally {
            setLoading(false);
        }
    };

    return (
        <DashboardLayout userRole="admin">
            <div className="space-y-6 max-w-2xl mx-auto">
                <h1 className="text-3xl font-bold">Platform Configuration</h1>

                <Card>
                    <CardHeader>
                        <CardTitle>Global Rates & Fees</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <form onSubmit={handleSubmit} className="space-y-6">
                            <div className="space-y-2">
                                <Label htmlFor="commission_rate">Platform Commission (%)</Label>
                                <Input 
                                    id="commission_rate"
                                    name="commission_rate"
                                    type="number" 
                                    step="0.01" 
                                    value={settings.commission_rate}
                                    onChange={handleChange}
                                    placeholder="10.00"
                                />
                                <p className="text-sm text-gray-500">
                                    Percentage of each booking deducted as platform fee.
                                </p>
                            </div>

                            <div className="space-y-2">
                                <Label htmlFor="video_call_rate_per_min">Default Video Call Rate (NPR/min)</Label>
                                <Input 
                                    id="video_call_rate_per_min"
                                    name="video_call_rate_per_min"
                                    type="number" 
                                    step="0.01"
                                    value={settings.video_call_rate_per_min}
                                    onChange={handleChange}
                                    placeholder="15.00"
                                />
                                <p className="text-sm text-gray-500">
                                    Base rate for video consultations if not set by Pandit.
                                </p>
                            </div>

                            <Button type="submit" disabled={loading} className="w-full">
                                {loading ? 'Saving...' : 'Save Configuration'}
                            </Button>
                        </form>
                    </CardContent>
                </Card>
            </div>
        </DashboardLayout>
    );
};

export default AdminSettings;

import React, { useState, useEffect } from 'react';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Textarea } from '@/components/ui/textarea';
import { useAuth } from '@/hooks/useAuth';
import { fetchAdminSiteContent, updateSiteContent, type SiteContentItem } from '@/lib/api';
import { FileText, Save, CheckCircle, AlertCircle, RefreshCw, Type, Phone, Mail, MapPin, Megaphone, Footprints } from 'lucide-react';
import { motion } from 'framer-motion';

const ICON_MAP: Record<string, any> = {
    hero_title: Type,
    hero_subtitle: Type,
    about_title: Type,
    about_text: FileText,
    contact_address: MapPin,
    contact_phone: Phone,
    contact_email: Mail,
    announcement: Megaphone,
    footer_text: Footprints,
};

export default function AdminSiteContent() {
    const { role } = useAuth();
    const [contents, setContents] = useState<SiteContentItem[]>([]);
    const [availableKeys, setAvailableKeys] = useState<{ key: string; label: string }[]>([]);
    const [existingKeys, setExistingKeys] = useState<string[]>([]);
    const [editValues, setEditValues] = useState<Record<string, string>>({});
    const [loading, setLoading] = useState(true);
    const [saving, setSaving] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    useEffect(() => {
        loadContent();
    }, []);

    const loadContent = async () => {
        setLoading(true);
        try {
            const data = await fetchAdminSiteContent();
            setContents(data.contents);
            setAvailableKeys(data.available_keys);
            setExistingKeys(data.existing_keys);

            // Initialize edit values from existing content
            const values: Record<string, string> = {};
            data.contents.forEach(c => {
                values[c.key] = c.value;
            });
            // Also initialize empty values for missing keys
            data.available_keys.forEach(k => {
                if (!values[k.key]) values[k.key] = '';
            });
            setEditValues(values);
        } catch (err) {
            console.error('Failed to load site content:', err);
        } finally {
            setLoading(false);
        }
    };

    const handleSaveAll = async () => {
        setSaving(true);
        setMessage(null);
        try {
            const items = Object.entries(editValues).map(([key, value]) => ({ key, value }));
            await updateSiteContent(items);
            setMessage({ type: 'success', text: 'All content saved successfully!' });
            loadContent(); // Refresh
        } catch (err: any) {
            setMessage({ type: 'error', text: err.message || 'Failed to save content' });
        } finally {
            setSaving(false);
        }
    };

    const isLongField = (key: string) => ['about_text', 'announcement', 'footer_text', 'hero_subtitle'].includes(key);

    if (loading) {
        return (
            <DashboardLayout userRole={role === 'superadmin' ? 'admin' : (role as any)}>
                <div className="flex items-center justify-center h-64">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" />
                </div>
            </DashboardLayout>
        );
    }

    return (
        <DashboardLayout userRole={role === 'superadmin' ? 'admin' : (role as any)}>
            <div className="p-6 max-w-5xl mx-auto space-y-6">
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold text-gray-900">Site Content</h1>
                        <p className="text-gray-500 mt-1">Edit your website's public-facing text and information</p>
                    </div>
                    <div className="flex gap-2">
                        <Button variant="outline" onClick={loadContent} disabled={loading}>
                            <RefreshCw className="h-4 w-4 mr-2" />
                            Refresh
                        </Button>
                        <Button onClick={handleSaveAll} disabled={saving} className="bg-orange-500 hover:bg-orange-600">
                            <Save className="h-4 w-4 mr-2" />
                            {saving ? 'Saving...' : 'Save All Changes'}
                        </Button>
                    </div>
                </div>

                {message && (
                    <div className={`flex items-center gap-2 p-3 rounded-lg text-sm ${
                        message.type === 'success'
                            ? 'bg-green-50 text-green-700 border border-green-200'
                            : 'bg-red-50 text-red-700 border border-red-200'
                    }`}>
                        {message.type === 'success' ? <CheckCircle className="h-4 w-4" /> : <AlertCircle className="h-4 w-4" />}
                        {message.text}
                    </div>
                )}

                {/* Content Cards */}
                <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    {availableKeys.map((keyInfo, idx) => {
                        const IconComponent = ICON_MAP[keyInfo.key] || FileText;
                        const existing = contents.find(c => c.key === keyInfo.key);

                        return (
                            <motion.div
                                key={keyInfo.key}
                                initial={{ opacity: 0, y: 20 }}
                                animate={{ opacity: 1, y: 0 }}
                                transition={{ delay: idx * 0.05 }}
                                className={isLongField(keyInfo.key) ? 'md:col-span-2' : ''}
                            >
                                <Card>
                                    <CardHeader className="pb-3">
                                        <CardTitle className="flex items-center gap-2 text-base">
                                            <IconComponent className="h-4 w-4 text-orange-500" />
                                            {keyInfo.label}
                                        </CardTitle>
                                        {existing && (
                                            <CardDescription className="text-xs">
                                                Last updated: {new Date(existing.updated_at).toLocaleDateString()}
                                                {existing.updated_by_name && ` by ${existing.updated_by_name}`}
                                            </CardDescription>
                                        )}
                                    </CardHeader>
                                    <CardContent>
                                        {isLongField(keyInfo.key) ? (
                                            <Textarea
                                                value={editValues[keyInfo.key] || ''}
                                                onChange={e => setEditValues(prev => ({
                                                    ...prev,
                                                    [keyInfo.key]: e.target.value
                                                }))}
                                                placeholder={`Enter ${keyInfo.label.toLowerCase()}...`}
                                                rows={4}
                                                className="resize-y"
                                            />
                                        ) : (
                                            <Input
                                                value={editValues[keyInfo.key] || ''}
                                                onChange={e => setEditValues(prev => ({
                                                    ...prev,
                                                    [keyInfo.key]: e.target.value
                                                }))}
                                                placeholder={`Enter ${keyInfo.label.toLowerCase()}...`}
                                            />
                                        )}
                                    </CardContent>
                                </Card>
                            </motion.div>
                        );
                    })}
                </div>

                {/* Bottom Save Button */}
                <div className="flex justify-end pt-4">
                    <Button onClick={handleSaveAll} disabled={saving} className="bg-orange-500 hover:bg-orange-600">
                        <Save className="h-4 w-4 mr-2" />
                        {saving ? 'Saving All...' : 'Save All Changes'}
                    </Button>
                </div>
            </div>
        </DashboardLayout>
    );
}

import React, { useEffect, useState } from 'react';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from '@/components/ui/table';
import { Button } from '@/components/ui/button';
import { Badge } from '@/components/ui/badge';
import axiosInstance from '@/lib/api-client';
import { useToast } from "@/hooks/use-toast";
import { format } from 'date-fns';
import { DataTablePagination } from "@/components/common/DataTablePagination";

interface User {
    id: number;
    phone_number: string;
    email: string;
    full_name: string;
    role: string;
    is_active: boolean;
    date_joined: string;
}

const AdminUsers = () => {
    const { toast } = useToast();
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState("");
    const [currentPage, setCurrentPage] = useState(1);
    const itemsPerPage = 10;
    const [editId, setEditId] = useState<number | null>(null);
    const [editForm, setEditForm] = useState<{ full_name: string; email: string; role: string }>({ full_name: "", email: "", role: "user" });

    useEffect(() => {
        fetchUsers();
    }, []);

    const fetchUsers = async () => {
        try {
            const res = await axiosInstance.get('/users/admin/users/');
            setUsers(res.data);
        } catch (error) {
            console.error(error);
            toast({ title: "Error", description: "Failed to load users", variant: "destructive" });
        } finally {
            setLoading(false);
        }
    };

    const toggleStatus = async (userId: number, currentStatus: boolean) => {
        try {
            const res = await axiosInstance.post(`/users/admin/users/${userId}/toggle-status/`);
            toast({ title: "Success", description: res.data.message });
            setUsers(users.map(u => u.id === userId ? { ...u, is_active: !currentStatus } : u));
        } catch (error) {
            toast({ title: "Error", description: "Failed to update user status", variant: "destructive" });
        }
    };

    const handleSearch = (e: React.ChangeEvent<HTMLInputElement>) => {
        setSearch(e.target.value);
        setCurrentPage(1);
    };

    const filteredUsers = users.filter(u =>
        (u.full_name || "").toLowerCase().includes(search.toLowerCase()) ||
        (u.email || "").toLowerCase().includes(search.toLowerCase())
    );

    const totalPages = Math.ceil(filteredUsers.length / itemsPerPage);
    const currentUsers = filteredUsers.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

    const handleEdit = (user: User) => {
        setEditId(user.id);
        setEditForm({ full_name: user.full_name, email: user.email, role: user.role });
    };

    const handleEditChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setEditForm(prev => ({ ...prev, [name]: value }));
    };

    const handleEditSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        try {
            await axiosInstance.put(`/users/admin/users/${editId}/`, editForm);
            toast({ title: "Success", description: "User updated" });
            setEditId(null);
            fetchUsers();
        } catch {
            toast({ title: "Error", description: "Failed to update user", variant: "destructive" });
        }
    };

    const handleDelete = async (id: number) => {
        if (window.confirm("Delete this user?")) {
            try {
                await axiosInstance.delete(`/users/admin/users/${id}/`);
                toast({ title: "Deleted", description: "User deleted" });
                fetchUsers();
            } catch {
                toast({ title: "Error", description: "Failed to delete user", variant: "destructive" });
            }
        }
    };

    return (
        <DashboardLayout userRole="admin">
            <div className="space-y-6">
                <div className="flex justify-between items-center">
                    <h1 className="text-3xl font-bold">User Management</h1>
                    <span className="text-muted-foreground">Total: {users.length}</span>
                </div>
                <Card className="mb-6">
                    <CardHeader>
                        <CardTitle>Search & Manage Users</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <input type="text" placeholder="Search users..." value={search} onChange={handleSearch} className="mb-4 p-2 border rounded w-full max-w-md" />
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>ID</TableHead>
                                    <TableHead>Name</TableHead>
                                    <TableHead>Email</TableHead>
                                    <TableHead>Role</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead>Joined</TableHead>
                                    <TableHead>Actions</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {loading ? (
                                    <TableRow>
                                        <TableCell colSpan={7} className="text-center h-24">Loading...</TableCell>
                                    </TableRow>
                                ) : filteredUsers.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={7} className="text-center h-24">No users found.</TableCell>
                                    </TableRow>
                                ) : (
                                    currentUsers.map((user) => (
                                        <TableRow key={user.id}>
                                            <TableCell>#{user.id}</TableCell>
                                            <TableCell>
                                                {editId === user.id ? (
                                                    <input name="full_name" value={editForm.full_name} onChange={handleEditChange} className="p-1 border rounded" />
                                                ) : user.full_name || 'N/A'}
                                            </TableCell>
                                            <TableCell>
                                                {editId === user.id ? (
                                                    <input name="email" value={editForm.email} onChange={handleEditChange} className="p-1 border rounded" />
                                                ) : user.email}
                                            </TableCell>
                                            <TableCell>
                                                {editId === user.id ? (
                                                    <input name="role" value={editForm.role} onChange={handleEditChange} className="p-1 border rounded" />
                                                ) : user.role}
                                            </TableCell>
                                            <TableCell>
                                                <span className={user.is_active ? "text-green-600" : "text-red-600"}>{user.is_active ? 'Active' : 'Blocked'}</span>
                                            </TableCell>
                                            <TableCell>{format(new Date(user.date_joined), 'MMM dd, yyyy')}</TableCell>
                                            <TableCell>
                                                {editId === user.id ? (
                                                    <>
                                                        <Button size="sm" onClick={handleEditSubmit}>Save</Button>
                                                        <Button size="sm" variant="outline" onClick={() => setEditId(null)}>Cancel</Button>
                                                    </>
                                                ) : (
                                                    <>
                                                        <Button size="sm" variant="outline" onClick={() => handleEdit(user)}>Edit</Button>
                                                        <Button size="sm" variant="destructive" onClick={() => handleDelete(user.id)}>Delete</Button>
                                                        <Button size="sm" variant={user.is_active ? "destructive" : "outline"} onClick={() => toggleStatus(user.id, user.is_active)}>
                                                            {user.is_active ? 'Block' : 'Unblock'}
                                                        </Button>
                                                    </>
                                                )}
                                            </TableCell>
                                        </TableRow>
                                    ))
                                )}
                            </TableBody>
                        </Table>
                        <DataTablePagination
                            currentPage={currentPage}
                            totalPages={totalPages}
                            onPageChange={setCurrentPage}
                        />
                    </CardContent>
                </Card>
            </div>
        </DashboardLayout>
    );
};

export default AdminUsers;

import React, { useState, useEffect } from 'react';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Label } from '@/components/ui/label';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { useAuth } from '@/hooks/useAuth';
import {
    fetchAdminUsers, createAdminUser, updateAdminUser, deleteAdminUser,
    type AdminUser,
} from '@/lib/api';
import {
    Shield, UserPlus, Trash2, ToggleLeft, ToggleRight,
    Crown, CheckCircle, AlertCircle, X, Users,
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';

const API_BASE = import.meta.env.VITE_API_BASE_URL || 'http://localhost:8000';

export default function ManageAdmins() {
    const { user, role } = useAuth();
    const [admins, setAdmins] = useState<AdminUser[]>([]);
    const [loading, setLoading] = useState(true);
    const [showCreateForm, setShowCreateForm] = useState(false);
    const [message, setMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

    // Create form state
    const [newEmail, setNewEmail] = useState('');
    const [newFullName, setNewFullName] = useState('');
    const [newPhone, setNewPhone] = useState('');
    const [newPassword, setNewPassword] = useState('');
    const [newRole, setNewRole] = useState<'admin' | 'superadmin'>('admin');
    const [creating, setCreating] = useState(false);

    useEffect(() => {
        loadAdmins();
    }, []);

    const loadAdmins = async () => {
        try {
            const data = await fetchAdminUsers();
            setAdmins(data);
        } catch (err: any) {
            setMessage({ type: 'error', text: err.message || 'Failed to load admins' });
        } finally {
            setLoading(false);
        }
    };

    const handleCreate = async () => {
        if (!newEmail || !newPassword) {
            setMessage({ type: 'error', text: 'Email and password are required' });
            return;
        }
        setCreating(true);
        setMessage(null);
        try {
            await createAdminUser({
                email: newEmail,
                full_name: newFullName,
                phone_number: newPhone,
                password: newPassword,
                role: newRole,
            });
            setMessage({ type: 'success', text: 'Admin created successfully!' });
            setShowCreateForm(false);
            setNewEmail('');
            setNewFullName('');
            setNewPhone('');
            setNewPassword('');
            setNewRole('admin');
            loadAdmins();
        } catch (err: any) {
            setMessage({ type: 'error', text: err.message || 'Failed to create admin' });
        } finally {
            setCreating(false);
        }
    };

    const handleToggleStatus = async (adminId: number) => {
        try {
            await updateAdminUser(adminId, { action: 'toggle_status' });
            loadAdmins();
            setMessage({ type: 'success', text: 'Status toggled successfully' });
        } catch (err: any) {
            setMessage({ type: 'error', text: err.message || 'Failed to toggle status' });
        }
    };

    const handleDelete = async (adminId: number, adminName: string) => {
        if (!window.confirm(`Are you sure you want to delete admin "${adminName}"? This cannot be undone.`)) return;
        try {
            await deleteAdminUser(adminId);
            loadAdmins();
            setMessage({ type: 'success', text: 'Admin deleted successfully' });
        } catch (err: any) {
            setMessage({ type: 'error', text: err.message || 'Failed to delete admin' });
        }
    };

    const handleRoleChange = async (adminId: number, newRole: string) => {
        try {
            await updateAdminUser(adminId, { action: 'change_role', role: newRole });
            loadAdmins();
            setMessage({ type: 'success', text: 'Role updated successfully' });
        } catch (err: any) {
            setMessage({ type: 'error', text: err.message || 'Failed to change role' });
        }
    };

    const superadminCount = admins.filter(a => a.role === 'superadmin').length;
    const adminCount = admins.filter(a => a.role === 'admin').length;

    if (loading) {
        return (
            <DashboardLayout userRole="admin">
                <div className="flex items-center justify-center h-64">
                    <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-orange-500" />
                </div>
            </DashboardLayout>
        );
    }

    return (
        <DashboardLayout userRole="admin">
            <div className="p-6 max-w-5xl mx-auto space-y-6">
                <div className="flex items-center justify-between">
                    <div>
                        <h1 className="text-3xl font-bold text-gray-900">Manage Admins</h1>
                        <p className="text-gray-500 mt-1">Add, remove, and manage administrator accounts</p>
                    </div>
                    <Button
                        onClick={() => setShowCreateForm(!showCreateForm)}
                        className="bg-orange-500 hover:bg-orange-600"
                    >
                        {showCreateForm ? <X className="h-4 w-4 mr-2" /> : <UserPlus className="h-4 w-4 mr-2" />}
                        {showCreateForm ? 'Cancel' : 'Add Admin'}
                    </Button>
                </div>

                {/* Stats */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <Card>
                        <CardContent className="pt-6">
                            <div className="flex items-center gap-3">
                                <div className="p-3 rounded-xl bg-purple-100">
                                    <Crown className="h-6 w-6 text-purple-600" />
                                </div>
                                <div>
                                    <p className="text-sm text-gray-500">Super Admins</p>
                                    <p className="text-2xl font-bold">{superadminCount}</p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="pt-6">
                            <div className="flex items-center gap-3">
                                <div className="p-3 rounded-xl bg-blue-100">
                                    <Shield className="h-6 w-6 text-blue-600" />
                                </div>
                                <div>
                                    <p className="text-sm text-gray-500">Regular Admins</p>
                                    <p className="text-2xl font-bold">{adminCount}</p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardContent className="pt-6">
                            <div className="flex items-center gap-3">
                                <div className="p-3 rounded-xl bg-orange-100">
                                    <Users className="h-6 w-6 text-orange-600" />
                                </div>
                                <div>
                                    <p className="text-sm text-gray-500">Total Admins</p>
                                    <p className="text-2xl font-bold">{admins.length}</p>
                                </div>
                            </div>
                        </CardContent>
                    </Card>
                </div>

                {message && (
                    <div className={`flex items-center gap-2 p-3 rounded-lg text-sm ${
                        message.type === 'success'
                            ? 'bg-green-50 text-green-700 border border-green-200'
                            : 'bg-red-50 text-red-700 border border-red-200'
                    }`}>
                        {message.type === 'success' ? <CheckCircle className="h-4 w-4" /> : <AlertCircle className="h-4 w-4" />}
