}

import React, { useState, useEffect } from 'react';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { Badge } from '@/components/ui/badge';
import { Loader2, CheckCircle, XCircle, FileText, Phone, Mail } from 'lucide-react';
import axios from 'axios';
import { motion } from 'framer-motion';

interface PendingPandit {
  id: number;
  full_name: string;
  phone_number: string;
  email: string;
  expertise: string;
  language: string;
  experience_years: number;
  bio: string;
  verification_status: string;
  certification_file_url: string;
  date_joined: string;
}

const AdminVerificationDashboard: React.FC = () => {
  const [pandits, setPandits] = useState<PendingPandit[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [actionLoading, setActionLoading] = useState<number | null>(null);
  const [successMessage, setSuccessMessage] = useState<string | null>(null);
  const [selectedPandit, setSelectedPandit] = useState<PendingPandit | null>(null);
  const [rejectReason, setRejectReason] = useState('');

  useEffect(() => {
    fetchPendingPandits();
  }, []);

  const fetchPendingPandits = async () => {
    try {
      setLoading(true);
      const token = localStorage.getItem('token');
      const response = await axios.get(
        'http://localhost:8000/api/pandits/pending/',
        {
          headers: {
            'Authorization': `Bearer ${token}`,
          },
        }
      );
      setPandits(response.data.results || []);
      setError(null);
    } catch (err: any) {
      setError(err.response?.data?.detail || 'Failed to load pending pandits');
      setPandits([]);
    } finally {
      setLoading(false);
    }
  };

  const handleApprovePandit = async (panditId: number) => {
    try {
      setActionLoading(panditId);
      const token = localStorage.getItem('token');
      await axios.post(
        `http://localhost:8000/api/pandits/${panditId}/verify/`,
        { notes: 'Approved by admin' },
        {
          headers: {
            'Authorization': `Bearer ${token}`,
          },
        }
      );
      setSuccessMessage('Pandit approved successfully!');
      fetchPendingPandits();
      setSelectedPandit(null);
    } catch (err: any) {
      setError(err.response?.data?.detail || 'Failed to approve pandit');
    } finally {
      setActionLoading(null);
    }
  };

  const handleRejectPandit = async (panditId: number) => {
    if (!rejectReason.trim()) {
      setError('Please provide a reason for rejection');
      return;
    }

    try {
      setActionLoading(panditId);
      const token = localStorage.getItem('token');
      await axios.post(
        `http://localhost:8000/api/pandits/${panditId}/reject/`,
        { reason: rejectReason },
        {
          headers: {
            'Authorization': `Bearer ${token}`,
          },
        }
      );
      setSuccessMessage('Pandit rejected successfully!');
      fetchPendingPandits();
      setSelectedPandit(null);
      setRejectReason('');
    } catch (err: any) {
      setError(err.response?.data?.detail || 'Failed to reject pandit');
    } finally {
      setActionLoading(null);
    }
  };

  if (loading) {
    return (
      <div className="flex justify-center items-center min-h-screen">
        <Loader2 className="h-8 w-8 animate-spin text-orange-600" />
      </div>
    );
  }

  return (
    <div className="container mx-auto py-10 px-4">
      <div className="mb-8">
        <h1 className="text-3xl font-bold text-gray-900 mb-2">Pandit Verification</h1>
        <p className="text-gray-600">Review and approve pending pandit registrations</p>
      </div>

      {error && (
        <Alert variant="destructive" className="mb-6">
          <AlertDescription>{error}</AlertDescription>
        </Alert>
      )}

      {successMessage && (
        <Alert className="mb-6 bg-green-50 border-green-200">
          <AlertDescription className="text-green-800">{successMessage}</AlertDescription>
        </Alert>
      )}

      <div className="grid gap-6">
        {pandits.length === 0 ? (
          <Card>
            <CardContent className="pt-12 text-center">
              <p className="text-gray-500 text-lg">No pending pandits for verification</p>
            </CardContent>
          </Card>
        ) : (
          pandits.map((pandit) => (
            <motion.div
              key={pandit.id}
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.3 }}
            >
              <Card className="overflow-hidden hover:shadow-lg transition-shadow">
                <CardHeader className="bg-gradient-to-r from-orange-50 to-yellow-50">
                  <div className="flex justify-between items-start">
                    <div>
                      <CardTitle className="text-xl">{pandit.full_name}</CardTitle>
                      <p className="text-sm text-gray-600 mt-1">{pandit.expertise}</p>
                    </div>
                    <Badge variant="secondary" className="bg-yellow-100 text-yellow-800">
                      {pandit.verification_status}
                    </Badge>
                  </div>
                </CardHeader>

                <CardContent className="pt-6">
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-6">
                    {/* Contact Info */}
                    <div className="space-y-3">
                      <div className="flex items-center gap-3">
                        <Phone className="h-4 w-4 text-gray-600" />
                        <span className="text-sm">{pandit.phone_number}</span>
                      </div>
                      {pandit.email && (
                        <div className="flex items-center gap-3">
                          <Mail className="h-4 w-4 text-gray-600" />
                          <span className="text-sm">{pandit.email}</span>
                        </div>
                      )}
                    </div>

                    {/* Experience Info */}
                    <div className="space-y-3">
                      <div>
                        <p className="text-sm font-semibold text-gray-700">Language</p>
                        <p className="text-sm text-gray-600">{pandit.language}</p>
                      </div>
                      <div>
                        <p className="text-sm font-semibold text-gray-700">Experience</p>
                        <p className="text-sm text-gray-600">{pandit.experience_years} years</p>
                      </div>
                    </div>
                  </div>

                  {/* Bio */}
                  {pandit.bio && (
                    <div className="mb-6">
                      <p className="text-sm font-semibold text-gray-700 mb-2">Bio</p>
                      <p className="text-sm text-gray-600">{pandit.bio}</p>
                    </div>
                  )}

                  {/* Certification File */}
                  {pandit.certification_file_url && (
                    <div className="mb-6">
                      <a
                        href={pandit.certification_file_url}
                        target="_blank"
                        rel="noopener noreferrer"
                        className="inline-flex items-center gap-2 px-3 py-2 bg-blue-50 text-blue-600 rounded-lg hover:bg-blue-100 transition-colors text-sm"
                      >
                        <FileText className="h-4 w-4" />
                        View Certification
                      </a>
                    </div>
                  )}

                  {/* Action Buttons */}
                  <div className="flex gap-3">
                    <Button
                      onClick={() => handleApprovePandit(pandit.id)}
                      disabled={actionLoading === pandit.id}
                      className="flex-1 bg-green-600 hover:bg-green-700"
                    >
                      {actionLoading === pandit.id ? (
                        <Loader2 className="h-4 w-4 animate-spin" />
                      ) : (
                        <>
                          <CheckCircle className="h-4 w-4 mr-2" />
                          Approve
                        </>
                      )}
                    </Button>

                    <Button
                      onClick={() => setSelectedPandit(pandit)}
                      variant="outline"
                      className="flex-1 border-red-200 hover:bg-red-50"
                    >
                      <XCircle className="h-4 w-4 mr-2" />
                      Reject
                    </Button>
                  </div>
                </CardContent>
              </Card>
            </motion.div>
          ))
        )}
      </div>

      {/* Rejection Modal */}
      {selectedPandit && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4 z-50">
          <motion.div
            initial={{ scale: 0.95, opacity: 0 }}
            animate={{ scale: 1, opacity: 1 }}
            className="bg-white rounded-lg max-w-md w-full p-6"
          >
            <h3 className="text-lg font-semibold mb-4">
              Reject {selectedPandit.full_name}?
            </h3>

            <textarea
              value={rejectReason}
              onChange={(e) => setRejectReason(e.target.value)}
              placeholder="Provide reason for rejection..."
              className="w-full h-24 border border-gray-200 rounded-lg p-3 text-sm mb-4 focus:ring-2 focus:ring-orange-500"
            />

            <div className="flex gap-3">
              <Button
                onClick={() => setSelectedPandit(null)}
                variant="outline"
                className="flex-1"
              >
                Cancel
              </Button>
              <Button
                onClick={() => handleRejectPandit(selectedPandit.id)}
                disabled={!rejectReason.trim() || actionLoading === selectedPandit.id}
                className="flex-1 bg-red-600 hover:bg-red-700"
              >
                {actionLoading === selectedPandit.id ? (
                  <Loader2 className="h-4 w-4 animate-spin" />
                ) : (
                  'Reject'
                )}
              </Button>
            </div>
          </motion.div>
        </div>
      )}
    </div>
  );
};

export default AdminVerificationDashboard;

import React, { useState, useEffect } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { LoadingSpinner } from '@/components/common/LoadingSpinner';
import { useAuth } from '@/hooks/useAuth';
import { AuthLayout } from '@/components/layout/AuthLayout';
import { Eye, EyeOff } from 'lucide-react';
import { Checkbox } from '@/components/ui/checkbox';
import { motion } from 'framer-motion';
import { FaPhone, FaEnvelope, FaUser, FaLock } from 'react-icons/fa';
import { useToast } from '@/hooks/use-toast';
import { GoogleLogin } from '@react-oauth/google';

const itemVariants = {
  hidden: { opacity: 0, x: -20 },
  visible: {
    opacity: 1,
    x: 0,
    transition: { staggerChildren: 0.1 }
  }
};

const LoginPage: React.FC = () => {
  const { requestOtp, passwordLogin, googleLogin, token, role } = useAuth();
  const navigate = useNavigate();
  const { toast } = useToast();
  const [loginMethod, setLoginMethod] = useState<'otp' | 'password'>('password');
  // New state for input type toggle (Phone / Email / Username)
  const [inputType, setInputType] = useState<'phone' | 'email' | 'username'>('email');

  const [phone, setPhone] = useState('');
  const [email, setEmail] = useState('');
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [rememberMe, setRememberMe] = useState(false);
  const [hasJustLoggedIn, setHasJustLoggedIn] = useState(false);

  // Redirect if already logged in or after successful login
  useEffect(() => {
    if (token) {
      if (hasJustLoggedIn && role) {
        // Redirect based on role
        if (role === 'admin' || role === 'superadmin') {
          navigate('/admin/dashboard', { replace: true });
        } else if (role === 'pandit') {
          navigate('/pandit/dashboard', { replace: true });
        } else {
          navigate('/dashboard', { replace: true });
        }
        setHasJustLoggedIn(false);
      } else if (!hasJustLoggedIn && !loading) {
        // Already logged in - session restore
        if (role === 'admin' || role === 'superadmin') {
          navigate('/admin/dashboard', { replace: true });
        } else if (role === 'pandit') {
          navigate('/pandit/dashboard', { replace: true });
        } else {
          navigate('/dashboard', { replace: true });
        }
      }
    }
  }, [token, role, navigate, hasJustLoggedIn, loading]);

  const handleRequestOtp = async () => {
    setError(null);
    setLoading(true);
    try {
      // Determine payload based on input type
      if (inputType === 'phone') {
        await requestOtp(phone);
      } else {
        await requestOtp(inputType === 'email' ? email : phone);
      }

      toast({
        title: "OTP Sent!",
        description: `Verification code sent to your ${inputType}. Please check and enter it.`,
        variant: "default",
      });
      navigate('/otp-verification', {
        state: {
          phone_number: inputType === 'phone' ? phone : undefined,
          email: inputType === 'email' ? email : undefined,
          flow: 'login'
        }
      });
    } catch (err: any) {
      // ... err handling
      setError(err?.message || 'Failed to request OTP');
      setLoading(false);
    }
  };

  const handlePasswordLogin = async () => {
    setError(null);
    setLoading(true);
    try {
      const identifier = inputType === 'email' ? email : inputType === 'username' ? username : phone;
      await passwordLogin(identifier, password);
      // Show success toast
      toast({
        title: "Login Successful!",
        description: "Welcome back! Redirecting to your dashboard...",
        variant: "default",
      });
      // Set flag to trigger redirect in useEffect after context updates
      setHasJustLoggedIn(true);
    } catch (err: any) {
      setError(err?.message || 'Login failed');
      setLoading(false);
    }
  };

  return (
    <AuthLayout title="Welcome" subtitle="Please login here">
      <motion.div className="space-y-6" variants={itemVariants}>
        {/* Login Method Toggle - styled as subtle tabs */}
        <motion.div className="flex bg-gray-100 p-1 rounded-lg" variants={itemVariants}>
          <button
            type="button"
            onClick={() => {
              setLoginMethod('password');
              setError(null);
            }}
            className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${loginMethod === 'password'
              ? 'bg-white text-primary shadow-sm'
              : 'text-gray-500 hover:text-gray-700'
              }`}
          >
            Password Login
          </button>
          <button
            type="button"
            onClick={() => {
              setLoginMethod('otp');
              setError(null);
              setPassword('');
            }}
            className={`flex-1 py-1.5 text-sm font-medium rounded-md transition-all ${loginMethod === 'otp'
              ? 'bg-white text-primary shadow-sm'
              : 'text-gray-500 hover:text-gray-700'
              }`}
          >
            OTP Login
          </button>
        </motion.div>

        {/* Inputs */}
        <motion.div className="space-y-4" variants={itemVariants}>
          <div className="space-y-2">
            {/* Input Type Toggle for BOTH OTP and Password Mode */}
            <div className="flex space-x-4 mb-2">
              <label className="flex items-center space-x-2 text-sm cursor-pointer">
                <input
                  type="radio"
                  checked={inputType === 'phone'}
                  onChange={() => setInputType('phone')}
                  className="text-primary"
                />
                <span>Phone</span>
              </label>
              <label className="flex items-center space-x-2 text-sm cursor-pointer">
                <input
                  type="radio"
                  checked={inputType === 'email'}
                  onChange={() => setInputType('email')}
                  className="text-primary"
                />
                <span>Email</span>
              </label>
              <label className="flex items-center space-x-2 text-sm cursor-pointer">
                <input
                  type="radio"
                  checked={inputType === 'username'}
                  onChange={() => setInputType('username')}
                  className="text-primary"
                />
                <span>Username</span>
              </label>
            </div>

            <Label htmlFor="identifier">
              {inputType === 'phone' ? 'Phone Number' : inputType === 'email' ? 'Email Address' : 'Username'}
            </Label>

            {inputType === 'phone' ? (
              <div className="relative group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-orange-500 transition-colors">
                  <FaPhone className="w-4 h-4" />
                </span>
                <Input
                  id="phone"
                  value={phone}
                  onChange={(e) => setPhone(e.target.value)}
                  placeholder="Enter phone number"
                  type="tel"
                  className="h-14 rounded-2xl bg-gray-100/50 border-transparent focus:bg-white focus:ring-orange-500/20 focus:border-orange-200 pl-12 text-base transition-all"
                />
              </div>
            ) : inputType === 'email' ? (
              <div className="relative group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-orange-500 transition-colors">
                  <FaEnvelope className="w-4 h-4" />
                </span>
                <Input
                  id="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="Enter email address"
                  type="email"
                  className="h-14 rounded-2xl bg-gray-100/50 border-transparent focus:bg-white focus:ring-orange-500/20 focus:border-orange-200 pl-12 text-base transition-all"
                />
              </div>
            ) : (
              <div className="relative group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-orange-500 transition-colors">
                  <FaUser className="w-4 h-4" />
                </span>
                <Input
                  id="username"
                  value={username}
                  onChange={(e) => setUsername(e.target.value)}
                  placeholder="Enter username"
                  type="text"
                  className="h-14 rounded-2xl bg-gray-100/50 border-transparent focus:bg-white focus:ring-orange-500/20 focus:border-orange-200 pl-12 text-base transition-all"
                />
              </div>
            )}
          </div>

          {loginMethod === 'password' && (
            <div className="space-y-2">
              <Label htmlFor="password-login" className="text-gray-600 font-semibold px-1">Password</Label>
              <div className="relative group">
                <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-orange-500 transition-colors">
                  <FaLock className="w-4 h-4" />
                </span>
                <Input
                  id="password-login"
                  value={password}
                  onChange={(e) => setPassword(e.target.value)}
                  placeholder="Enter password"
                  type={showPassword ? 'text' : 'password'}
                  className="h-14 rounded-2xl bg-gray-100/50 border-transparent focus:bg-white focus:ring-orange-500/20 focus:border-orange-200 pl-12 pr-12 text-base transition-all"
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-orange-500 transition-colors"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
            </div>
          )}
        </motion.div>

        <motion.div className="space-y-6" variants={itemVariants}>

          {/* Remember Me & Forgot Password */}
          {loginMethod === 'password' && (
            <div className="flex items-center justify-between">
              <div className="flex items-center space-x-2">
                <Checkbox
                  id="remember-me"
                  checked={rememberMe}
                  onCheckedChange={(checked) => setRememberMe(checked as boolean)}
                />
                <label
                  htmlFor="remember-me"
                  className="text-sm font-medium leading-none peer-disabled:cursor-not-allowed peer-disabled:opacity-70 text-gray-600"
                >
                  Remember me
                </label>
              </div>
              <Link
                to="/auth/forgot-password"
                className="text-sm font-bold text-primary hover:underline"
              >
                Forgot Password?
              </Link>
            </div>
          )}

          {/* Action Button */}
          {loginMethod === 'password' ? (
            <Button
              onClick={handlePasswordLogin}
              disabled={
                loading ||
                (inputType === 'phone' && !phone) ||
                (inputType === 'email' && !email) ||
                (inputType === 'username' && !username) ||
                !password
              }
              className="w-full h-14 text-lg font-bold rounded-full bg-[#F97316] hover:bg-[#EA580C] text-white shadow-xl shadow-orange-200/50 transition-all active:scale-[0.98] border-none"
            >
              {loading ? <LoadingSpinner size={24} className="text-white" /> : 'Sign In'}
            </Button>
          ) : (
            <Button
              onClick={handleRequestOtp}
              disabled={
                loading ||
                (inputType === 'phone' && !phone) ||
                (inputType === 'email' && !email) ||
                (inputType === 'username' && !username)
              }
              className="w-full h-14 text-lg font-bold rounded-full bg-[#F97316] hover:bg-[#EA580C] text-white shadow-xl shadow-orange-200/50 transition-all active:scale-[0.98] border-none"
            >
              {loading ? <LoadingSpinner size={24} className="text-white" /> : 'Receive OTP'}
            </Button>
          )}

          {error && (
            <Alert variant="destructive">
              <AlertDescription>{error}</AlertDescription>
            </Alert>
          )}

          {/* Register Link + Pandit Registration */}
        </motion.div>

        <motion.div className="space-y-3 text-center" variants={itemVariants}>
          <div className="text-sm text-gray-500">
            Don't have an account?{' '}
            <Link to="/register" className="font-bold text-primary hover:underline">
              Register here
            </Link>
          </div>

          {/* Separator */}
          <div className="relative">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-gray-200"></div>
            </div>
            <div className="relative flex justify-center text-sm">
              <span className="px-2 bg-white text-gray-500">or</span>
            </div>
          </div>

          {/* Google Login Section */}
          <div className="flex flex-col items-center gap-4 pt-2">
            <p className="text-xs text-gray-400 uppercase tracking-widest font-bold">Or Continue With</p>
            <div className="w-full flex justify-center">
              <GoogleLogin
                onSuccess={async (credentialResponse) => {
                  if (credentialResponse.credential) {
                    setLoading(true);
                    try {
                      await googleLogin(credentialResponse.credential);
                      toast({
                        title: "Google Login Successful!",
                        description: "Welcome back! Redirecting...",
                      });
                      setHasJustLoggedIn(true);
                    } catch (err: any) {
                      setError(err.message || "Google login failed");
                    } finally {
                      setLoading(false);
                    }
                  }
                }}
                onError={() => {
                  setError("Google Login failed. Please try again.");
                }}
                useOneTap
                theme="outline"
                shape="pill"
                size="large"
                width={400}
                text="continue_with"
              />
            </div>
          </div>

          {/* Register as Pandit Button */}
          <div className="pt-4">
            <Link to="/pandit/register">
              <Button
                variant="outline"
                className="w-full h-12 text-base rounded-xl border-orange-200 hover:bg-orange-50"
              >
                Register as Pandit
              </Button>
            </Link>
          </div>
        </motion.div>
      </motion.div>
    </AuthLayout>
  );
};

export default LoginPage;

import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { Input } from '@/components/ui/input';
import { Button } from '@/components/ui/button';
import { Label } from '@/components/ui/label';
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from '@/components/ui/select';
import { Alert, AlertDescription } from '@/components/ui/alert';
import { LoadingSpinner } from '@/components/common/LoadingSpinner';
import { AuthLayout } from '@/components/layout/AuthLayout';
import { Upload, FileText } from 'lucide-react';
import { FaUser, FaPhone, FaEnvelope, FaLanguage, FaBriefcase } from 'react-icons/fa';
import { useToast } from '@/hooks/use-toast';
import { GoogleLogin } from '@react-oauth/google';
import { useAuth } from '@/hooks/useAuth';
import apiClient from '@/lib/api-client';

const PanditRegisterPage: React.FC = () => {
  const navigate = useNavigate();
  const { toast } = useToast();
  const { googleLogin, user } = useAuth();
  const [formData, setFormData] = useState({
    full_name: '',
    phone_number: '',
    email: '',
    password: '',
    expertise: [] as string[], // Changed to array
    language: '',
    experience_years: '',
    bio: '',
    certification_file: null as File | null,
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [success, setSuccess] = useState<string | null>(null);
  const [fileSelected, setFileSelected] = useState(false);
  const [showPassword, setShowPassword] = useState(false);

  const expertiseOptions = [
    'Vedic Rituals',
    'Astrology & Kundali',
    'Marriage Ceremonies',
    'Griha Pravesh',
    'Naming Ceremony',
    'Funeral Rites',
    'Satyanarayan Puja',
    'Lakshmi Puja',
    'Ganesh Puja',
    'Navgraha Puja',
    'Rudrabhishek',
    'Thread Ceremony',
    'All Ceremonies'
  ];

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleExpertiseChange = (expertise: string) => {
    setFormData(prev => {
      const newExpertise = prev.expertise.includes(expertise)
        ? prev.expertise.filter(e => e !== expertise)
        : [...prev.expertise, expertise];
      return { ...prev, expertise: newExpertise };
    });
  };

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files[0]) {
      setFormData(prev => ({
        ...prev,
        certification_file: e.target.files![0]
      }));
      setFileSelected(true);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setError(null);
    setSuccess(null);
    setLoading(true);

    try {
      // Create FormData for multipart file upload
      const submitData = new FormData();
      submitData.append('full_name', formData.full_name.trim());
      submitData.append('phone_number', formData.phone_number.trim());
      submitData.append('email', formData.email.trim());
      submitData.append('password', formData.password);
      submitData.append('expertise', formData.expertise.join(', ')); // Join multiple selections
      submitData.append('language', formData.language.trim());
      submitData.append('experience_years', formData.experience_years);
      submitData.append('bio', formData.bio.trim());

      if (formData.certification_file) {
        submitData.append('certification_file', formData.certification_file);
      } else {
        throw new Error('Certification file is required');
      }

      // Send to backend
      await apiClient.post(
        '/pandits/register/',
        submitData,
        {
          headers: {
            'Content-Type': 'multipart/form-data',
          },
        }
      );

      toast({
        title: "Registration Submitted!",
        description: "Your documents are under review. We will contact you shortly.",
        variant: "default",
      });

      setSuccess(
        'Registration successful! Your documents are under review. We will contact you shortly.'
      );

      // Redirect to login after 3 seconds
      setTimeout(() => navigate('/login'), 3000);
    } catch (err: any) {
      const errorMsg = err.response?.data?.detail || err.response?.data?.certification_file?.[0] || err.message || 'Registration failed';
      setError(errorMsg);
    } finally {
      setLoading(false);
    }
  };

  return (
    <AuthLayout title="Register as Pandit" subtitle="Share your expertise with seekers">
      <div className="mb-8 space-y-4">
        <p className="text-xs text-gray-400 uppercase tracking-widest font-bold text-center">Faster Application</p>
        <div className="flex justify-center">
          <GoogleLogin
            onSuccess={async (credentialResponse) => {
              if (credentialResponse.credential) {
                setLoading(true);
                try {
                  const resp = await googleLogin(credentialResponse.credential);
                  // Pre-fill form from Google identity
                  if (resp && resp.user) {
                    setFormData(prev => ({
                      ...prev,
                      full_name: resp.user.full_name || prev.full_name,
                      email: resp.user.email || prev.email,
                    }));
                    toast({
                      title: "Identity Verified!",
                      description: "We've pre-filled your name and email. Please complete the rest of the form.",
                    });
                  }
                } catch (err: any) {
                  setError(err.message || "Google authentication failed");
                } finally {
                  setLoading(false);
                }
              }
            }}
            onError={() => {
              setError("Google authentication failed. Please try again.");
            }}
            theme="outline"
            shape="pill"
            size="large"
            width="100%"
            text="continue_with"
          />
        </div>
        <div className="relative">
          <div className="absolute inset-0 flex items-center">
            <div className="w-full border-t border-gray-100"></div>
          </div>
          <div className="relative flex justify-center text-xs">
            <span className="px-2 bg-white text-gray-400">Or fill manually</span>
          </div>
        </div>
      </div>

      <form onSubmit={handleRegister} className="space-y-4">
        {/* Full Name */}
        <div className="space-y-2">
          <Label htmlFor="full_name" className="text-gray-600 font-semibold px-1">Full Name *</Label>
          <div className="relative group">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-orange-500 transition-colors">
              <FaUser className="w-4 h-4" />
            </span>
            <Input
              id="full_name"
              name="full_name"
              value={formData.full_name}
              onChange={handleInputChange}
              placeholder="Your full name"
              className="h-14 rounded-2xl bg-gray-100/50 border-transparent focus:bg-white focus:ring-orange-500/20 focus:border-orange-200 pl-12 text-base transition-all"
              required
            />
          </div>
        </div>

        {/* Email */}
        <div className="space-y-2">
          <Label htmlFor="email" className="text-gray-600 font-semibold px-1">Email Address *</Label>
          <div className="relative group">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-orange-500 transition-colors">
              <FaEnvelope className="w-4 h-4" />
            </span>
            <Input
              id="email"
              name="email"
              type="email"
              value={formData.email}
              onChange={handleInputChange}
              placeholder="your@email.com"
              className="h-14 rounded-2xl bg-gray-100/50 border-transparent focus:bg-white focus:ring-orange-500/20 focus:border-orange-200 pl-12 text-base transition-all"
              required
            />
          </div>
        </div>

        {/* Phone Number */}
        <div className="space-y-2">
          <Label htmlFor="phone_number" className="text-gray-600 font-semibold px-1">Phone Number (Optional)</Label>
          <div className="relative group">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-orange-500 transition-colors">
              <FaPhone className="w-4 h-4" />
            </span>
            <Input
              id="phone_number"
              name="phone_number"
              value={formData.phone_number}
              onChange={handleInputChange}
              placeholder="9841234567"
              className="h-14 rounded-2xl bg-gray-100/50 border-transparent focus:bg-white focus:ring-orange-500/20 focus:border-orange-200 pl-12 text-base transition-all"
            />
          </div>
        </div>

        {/* Password */}
        <div className="space-y-2">
          <Label htmlFor="password" {...(!user && { className: "text-gray-600 font-semibold px-1" })}>
            Password {user ? '(Optional - you logged in already)' : '*'}
          </Label>
          <div className="relative group">
            <span className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-400 group-focus-within:text-orange-500 transition-colors">
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="11" x="3" y="11" rx="2" ry="2" /><path d="M7 11V7a5 5 0 0 1 10 0v4" /></svg>
            </span>
            <Input
              id="password"
              name="password"
              type={showPassword ? 'text' : 'password'}
              value={formData.password}
              onChange={handleInputChange}
              placeholder={user ? "Set a password for future use (optional)" : "Create a strong password"}
              className="h-14 rounded-2xl bg-gray-100/50 border-transparent focus:bg-white focus:ring-orange-500/20 focus:border-orange-200 pl-12 pr-12 text-base transition-all"
              required={!user}
              minLength={6}
            />
            <button
              type="button"
              onClick={() => setShowPassword(!showPassword)}
              className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-400 hover:text-orange-500 transition-colors"
            >
              {showPassword ? (
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17.94 17.94A10.07 10.07 0 0 1 12 20c-7 0-11-8-11-8a18.45 18.45 0 0 1 5.06-5.94M9.9 4.24A9.12 9.12 0 0 1 12 4c7 0 11 8 11 8a18.5 18.5 0 0 1-2.16 3.19m-6.72-1.07a3 3 0 1 1-4.24-4.24" /><line x1="1" x2="23" y1="1" y2="23" /></svg>
              ) : (
                <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M1 12s4-8 11-8 11 8 11 8-4 8-11 8-11-8-11-8z" /><circle cx="12" cy="12" r="3" /></svg>
              )}
            </button>
          </div>
          <p className="text-xs text-gray-500 px-1">Minimum 6 characters</p>
        </div>

        {/* Expertise */}
        <div className="space-y-2">
          <Label>Areas of Expertise * (Select all that apply)</Label>
          <div className="grid grid-cols-2 gap-3 p-3 bg-orange-50 rounded-lg border border-orange-200">
            {expertiseOptions.map((expertise) => (
              <label key={expertise} className="flex items-center gap-2 cursor-pointer">
                <input
                  type="checkbox"
                  checked={formData.expertise.includes(expertise)}
                  onChange={() => handleExpertiseChange(expertise)}
                  className="w-4 h-4 rounded border-gray-300 text-orange-600 focus:ring-orange-500"
                />
                <span className="text-sm text-gray-700">{expertise}</span>
              </label>
            ))}
          </div>
          {formData.expertise.length === 0 && (
            <p className="text-xs text-red-500">Please select at least one area of expertise</p>
          )}
          {formData.expertise.length > 0 && (
            <p className="text-xs text-green-600">Selected: {formData.expertise.join(', ')}</p>
          )}
        </div>

        {/* Language */}
        <div className="space-y-1">
          <Label htmlFor="language">Primary Language *</Label>
          <Select
            value={formData.language}
            onValueChange={(value) => setFormData(prev => ({ ...prev, language: value }))}
          >
            <SelectTrigger className="h-10 rounded-lg border-gray-200 text-sm">
              <SelectValue placeholder="Select your preferred language" />
            </SelectTrigger>
            <SelectContent>
              <SelectItem value="Nepali">Nepali</SelectItem>
              <SelectItem value="Hindi">Hindi</SelectItem>
              <SelectItem value="Sanskrit">Sanskrit</SelectItem>
              <SelectItem value="English">English</SelectItem>
              <SelectItem value="Maithili">Maithili</SelectItem>
            </SelectContent>
          </Select>
        </div>

        {/* Experience Years */}
        <div className="space-y-1">
          <Label htmlFor="experience_years">Years of Experience *</Label>
          <div className="relative">
            <span className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-500">
              <FaBriefcase className="w-5 h-5" />
            </span>
            <Input
              id="experience_years"
              name="experience_years"
              type="number"
              value={formData.experience_years}
              onChange={handleInputChange}
              placeholder="e.g., 10"
              min="0"
              max="100"
              className="h-10 rounded-lg border-gray-200 text-sm pl-10"
              required
            />
          </div>
        </div>

        {/* Bio */}
        <div className="space-y-1">
          <Label htmlFor="bio">Brief Bio (Optional)</Label>
          <textarea
            id="bio"
            name="bio"
            value={formData.bio}
            onChange={handleInputChange}
            placeholder="Tell us about yourself and your experience..."
            className="w-full h-24 rounded-lg border border-gray-200 px-3 py-2 text-sm focus:ring-2 focus:ring-orange-500 focus:border-transparent"
          />
        </div>

        {/* Certification File Upload */}
        <div className="space-y-1">
          <Label htmlFor="certification_file">Certification/License *</Label>
          <label
            htmlFor="certification_file"
            className={`flex items-center justify-center w-full h-32 rounded-lg border-2 border-dashed cursor-pointer transition-colors ${fileSelected
              ? 'border-green-400 bg-green-50'
              : 'border-orange-200 bg-orange-50 hover:bg-orange-100'
              }`}
          >
            <div className="flex flex-col items-center justify-center pt-5 pb-6">
              {fileSelected ? (
                <>
                  <FileText className="h-8 w-8 text-green-600 mb-2" />
                  <p className="text-sm font-semibold text-green-600">
                    {formData.certification_file?.name}
                  </p>
                  <p className="text-xs text-gray-500">Click to change</p>
                </>
              ) : (
                <>
                  <Upload className="h-8 w-8 text-orange-600 mb-2" />
                  <p className="text-sm font-semibold text-gray-700">Upload certification</p>
                  <p className="text-xs text-gray-500">PDF, JPG, PNG (max 5MB)</p>
                </>
              )}
            </div>
            <input
              id="certification_file"
              type="file"
              onChange={handleFileChange}
              accept=".pdf,.jpg,.jpeg,.png"
              className="hidden"
              required
            />
          </label>
        </div>

        {/* Error Alert */}
        {error && (
          <Alert variant="destructive">
            <AlertDescription>{error}</AlertDescription>
          </Alert>
        )}

        {/* Success Alert */}
        {success && (
          <Alert className="bg-green-50 border-green-200">
            <AlertDescription className="text-green-800">{success}</AlertDescription>
          </Alert>
        )}

        {/* Submit Button */}
        <Button
          type="submit"
          disabled={loading || !fileSelected}
          className="w-full h-14 text-lg font-bold rounded-full bg-[#F97316] hover:bg-[#EA580C] text-white shadow-xl shadow-orange-200/50 transition-all active:scale-[0.98] border-none mt-6"
        >
          {loading ? (
            <LoadingSpinner size={24} className="text-white" />
          ) : (
            'Apply for Verification'
          )}
        </Button>

        {/* Back to Login */}
        <div className="text-center text-sm text-gray-500">
          Already have an account?{' '}
          <Link to="/login" className="font-bold text-orange-600 hover:underline">
            Login here
          </Link>
        </div>
      </form>
    </AuthLayout>
  );
};

