import { Star, StarHalf } from "lucide-react";

interface RatingStarsProps {
    rating: number;
    count?: number; // Optional review count to display
    color?: string;
    size?: number;
}

export const RatingStars = ({ rating, count, color = "text-yellow-500", size = 16 }: RatingStarsProps) => {
    // Fill stars
    const fullStars = Math.floor(rating);
    const hasHalfStar = rating % 1 !== 0; // Simplified

    return (
        <div className="flex items-center gap-1">
            <div className="flex">
                {[...Array(5)].map((_, i) => (
                    <Star
                        key={i}
                        size={size}
                        className={`${i < fullStars
                                ? `${color} fill-current`
                                : i === fullStars && rating > i ? `${color} fill-current opacity-50` // Rough half star approximation or use distinct icon
                                    : "text-gray-300"
                            }`}
                    />
                ))}
            </div>
            {count !== undefined && (
                <span className="text-sm text-gray-500 ml-1">({count})</span>
            )}
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Card, CardContent, CardHeader, CardTitle, CardDescription, CardFooter } from '@/components/ui/card';
import { Textarea } from '@/components/ui/textarea';
import { Button } from '@/components/ui/button';
import { Loader2, MessageSquareHeart, Send, Star, CheckCircle2 } from 'lucide-react';
import { fetchSiteReviews, submitSiteReview } from '@/lib/api';
import { useToast } from '@/hooks/use-toast';

const PanditAppFeedback = () => {
  const { toast } = useToast();
  const [feedbackRating, setFeedbackRating] = useState(0);
  const [feedbackComment, setFeedbackComment] = useState('');
  const [feedbackHover, setFeedbackHover] = useState(0);
  const [feedbackSubmitting, setFeedbackSubmitting] = useState(false);
  const [feedbackSubmitted, setFeedbackSubmitted] = useState(false);
  const [appAvgRating, setAppAvgRating] = useState(0);
  const [appTotalReviews, setAppTotalReviews] = useState(0);

  useEffect(() => {
    fetchSiteReviews()
      .then((data) => {
        setAppAvgRating(data.average_rating);
        setAppTotalReviews(data.total_reviews);
      })
      .catch(() => undefined);
  }, []);

  const handleFeedbackSubmit = async () => {
    if (feedbackRating === 0) {
      toast({ title: 'Please select a rating', variant: 'destructive' });
      return;
    }
    if (!feedbackComment.trim()) {
      toast({ title: 'Please write your feedback', variant: 'destructive' });
      return;
    }

    setFeedbackSubmitting(true);
    try {
      await submitSiteReview({ rating: feedbackRating, comment: feedbackComment.trim() });
      setFeedbackSubmitted(true);
      toast({ title: 'Feedback submitted', description: 'Thank you for your feedback.' });
    } catch (err: any) {
      const msg = err?.response?.data?.detail || 'Failed to submit feedback.';
      toast({ title: 'Error', description: msg, variant: 'destructive' });
    } finally {
      setFeedbackSubmitting(false);
    }
  };

  return (
    <DashboardLayout userRole="pandit">
      <div className="space-y-6 max-w-3xl">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">App Feedback</h1>
          <p className="text-muted-foreground">Rate your experience and suggest improvements for PanditYatra.</p>
        </div>

        <Card className="border-orange-100 bg-gradient-to-r from-orange-50/50 to-white">
          <CardContent className="pt-6">
            <div className="flex items-center gap-4">
              <div className="p-3 rounded-full bg-orange-100">
                <Star className="h-6 w-6 text-orange-600 fill-orange-600" />
              </div>
              <div>
                <h3 className="font-bold text-lg">PanditYatra App Rating</h3>
                <div className="flex items-center gap-2 mt-1">
                  <div className="flex gap-0.5">
                    {[1, 2, 3, 4, 5].map((s) => (
                      <Star key={s} size={16} className={s <= Math.round(appAvgRating) ? 'text-yellow-400 fill-yellow-400' : 'text-gray-300'} />
                    ))}
                  </div>
                  <span className="font-bold text-lg">{appAvgRating}</span>
                  <span className="text-sm text-muted-foreground">({appTotalReviews} reviews)</span>
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {feedbackSubmitted ? (
          <Card className="border-green-200 bg-green-50/30">
            <CardContent className="py-12 text-center">
              <CheckCircle2 className="h-16 w-16 text-green-500 mx-auto mb-4" />
              <h3 className="text-xl font-bold text-green-800">Thank You!</h3>
              <p className="text-green-600 mt-2">Your feedback has been submitted successfully.</p>
            </CardContent>
          </Card>
        ) : (
          <Card>
            <CardHeader>
              <CardTitle className="flex items-center gap-2">
                <MessageSquareHeart className="h-5 w-5 text-orange-600" />
                Share Your Feedback
              </CardTitle>
              <CardDescription>How has your experience been as a pandit on our platform?</CardDescription>
            </CardHeader>
            <CardContent className="space-y-5">
              <div>
                <label className="text-sm font-medium text-slate-700 block mb-2">How would you rate PanditYatra?</label>
                <div className="flex gap-2">
                  {[1, 2, 3, 4, 5].map((s) => (
                    <button
                      key={s}
                      type="button"
                      onClick={() => setFeedbackRating(s)}
                      onMouseEnter={() => setFeedbackHover(s)}
                      onMouseLeave={() => setFeedbackHover(0)}
                      className="transition-transform hover:scale-125 p-1"
                    >
                      <Star
                        size={32}
                        className={s <= (feedbackHover || feedbackRating) ? 'text-yellow-400 fill-yellow-400 drop-shadow-sm' : 'text-gray-300'}
                      />
                    </button>
                  ))}
                </div>
              </div>

              <div>
                <label className="text-sm font-medium text-slate-700 block mb-1.5">Your Feedback</label>
                <Textarea
                  placeholder="Share what you like and what can be improved..."
                  value={feedbackComment}
                  onChange={(e) => setFeedbackComment(e.target.value)}
                  className="min-h-[120px] border-slate-200 focus:border-orange-400"
                  maxLength={500}
                />
                <p className="text-xs text-muted-foreground mt-1">{feedbackComment.length}/500</p>
              </div>
            </CardContent>
            <CardFooter>
              <Button
                onClick={handleFeedbackSubmit}
                disabled={feedbackSubmitting}
                className="w-full bg-orange-600 hover:bg-orange-700 text-white rounded-full font-semibold text-base py-5"
              >
                {feedbackSubmitting ? <Loader2 className="h-5 w-5 animate-spin mr-2" /> : <Send className="h-5 w-5 mr-2" />}
                Submit Feedback
              </Button>
            </CardFooter>
          </Card>
        )}
      </div>
    </DashboardLayout>
  );
};

export default PanditAppFeedback;

import React, { useEffect, useState } from 'react'
import { DashboardLayout } from '@/components/layout/DashboardLayout'
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Badge } from "@/components/ui/badge"
import { Button } from "@/components/ui/button"
import apiClient from '@/lib/api-client'
import { Video, Check, X } from 'lucide-react'
import { useToast } from "@/hooks/use-toast"

interface Booking {
  id: number;
  service_name: string;
  booking_date: string;
  booking_time: string;
  status: string;
  user_full_name: string;
  payment_status: boolean;
  payment_method?: string;
  transaction_id?: string;
  video_room_url?: string;
  daily_room_url?: string;
}

const PanditBookings = () => {
  const [bookings, setBookings] = useState<Booking[]>([]);
  const [loading, setLoading] = useState(true);
  const { toast } = useToast();

  useEffect(() => {
    fetchBookings();
  }, []);

  const fetchBookings = async () => {
    try {
      const response = await apiClient.get('/bookings/');
      setBookings(response.data.results || response.data);
    } catch (error) {
      console.error("Failed to load bookings", error);
    } finally {
      setLoading(false);
    }
  };

  const handleStatusUpdate = async (id: number, status: string) => {
    try {
      await apiClient.patch(`/bookings/${id}/update_status/`, { status });
      toast({ title: `Booking ${status.toLowerCase()}` });
      fetchBookings();
    } catch (error) {
      toast({ title: "Failed to update status", variant: "destructive" });
    }
  };

  return (
    <DashboardLayout userRole="pandit">
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">My Bookings</h1>
          <p className="text-muted-foreground">Manage your upcoming and past service requests.</p>
        </div>

        <div className="grid gap-4">
          {loading ? <p>Loading...</p> : bookings.length === 0 ? <p className="text-muted-foreground">No bookings found.</p> : bookings.map((booking) => (
            <Card key={booking.id}>
              <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                <CardTitle className="text-xl">{booking.service_name}</CardTitle>
                <Badge variant={booking.status === 'ACCEPTED' ? 'default' : booking.status === 'COMPLETED' ? 'secondary' : 'outline'}>
                  {booking.status}
                </Badge>
              </CardHeader>
              <CardContent>
                <div className="text-sm text-muted-foreground mb-4">
                  <p><span className="font-semibold">Client:</span> {booking.user_full_name}</p>
                  <p><span className="font-semibold">Date:</span> {booking.booking_date}</p>
                  <p><span className="font-semibold">Time:</span> {booking.booking_time}</p>
                  <p>
                    <span className="font-semibold">Payment:</span>{' '}
                    <span className={booking.payment_status ? 'text-green-700 font-medium' : 'text-yellow-700 font-medium'}>
                      {booking.payment_status ? `Paid${booking.payment_method ? ` (${booking.payment_method})` : ''}` : 'Unpaid'}
                    </span>
                  </p>
                  {booking.transaction_id && (
                    <p><span className="font-semibold">Transaction:</span> {booking.transaction_id}</p>
                  )}
                </div>
                <div className="flex gap-2">
                  {booking.status === 'PENDING' && (
                    <>
                      <Button size="sm" className="bg-green-600 hover:bg-green-700" onClick={() => handleStatusUpdate(booking.id, 'ACCEPTED')}>
                        <Check className="w-4 h-4 mr-1" /> Accept
                      </Button>
                      <Button size="sm" variant="destructive" onClick={() => handleStatusUpdate(booking.id, 'CANCELLED')}>
                        <X className="w-4 h-4 mr-1" /> Decline
                      </Button>
                    </>
                  )}
                  {booking.status === 'ACCEPTED' && (booking.daily_room_url || booking.video_room_url) && (
                    <Button size="sm" className="bg-green-600 hover:bg-green-700" onClick={() => window.open(booking.daily_room_url || booking.video_room_url, '_blank')}>
                      <Video className="w-4 h-4 mr-1" /> Start Puja
                    </Button>
                  )}
                  {booking.status === 'ACCEPTED' && (
                    <div className="flex gap-2">
                      <Button
                        size="sm"
                        variant="secondary"
                        className="bg-orange-50 text-orange-700 hover:bg-orange-100 border-orange-200"
                        onClick={async () => {
                          try {
                            await apiClient.post(`/video/generate-link/${booking.id}/`);
                            toast({ title: (booking.daily_room_url || booking.video_room_url) ? "Room regenerated successfully" : "Room generated successfully" });
                            fetchBookings();
                          } catch (error) {
                            toast({ title: "Failed to generate link", variant: "destructive" });
                          }
                        }}
                      >
                        <Video className="w-4 h-4 mr-1" /> 
                        { (booking.daily_room_url || booking.video_room_url) ? 'Regenerate Link' : 'Generate Link' }
                      </Button>
                      <Button size="sm" variant="outline" onClick={() => handleStatusUpdate(booking.id, 'COMPLETED')}>
                        Mark Completed
                      </Button>
                    </div>
                  )}
                </div>
              </CardContent>
            </Card>
          ))}
        </div>
      </div>
    </DashboardLayout>
  )
}

export default PanditBookings

