        type: 'booking' | 'block';
        status?: string;
        location?: string;
    };
}

export const PanditCalendar = () => {
    const [events, setEvents] = useState<CalendarEvent[]>([]);
    const [loading, setLoading] = useState(true);
    const { toast } = useToast();

    // Dialog State
    const [isDialogOpen, setIsDialogOpen] = useState(false);
    const [selectedDate, setSelectedDate] = useState<{ start: string; end: string } | null>(null);
    const [blockReason, setBlockReason] = useState('Unavailable');

    // Selected Event to Delete
    const [selectedBlockId, setSelectedBlockId] = useState<string | null>(null);

    const fetchEvents = async () => {
        setLoading(true);
        try {
            const res = await apiClient.get('/pandits/me/calendar/');
            setEvents(res.data);
        } catch (error) {
            console.error("Failed to fetch calendar", error);
            toast({
                title: "Error",
                description: "Failed to load schedule.",
                variant: "destructive"
            });
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchEvents();
    }, []);

    const handleDateSelect = (selectInfo: any) => {
        // Open Dialog
        setSelectedDate({
            start: selectInfo.startStr,
            end: selectInfo.endStr
        });
        setIsDialogOpen(true);
    };

    const handleEventClick = (clickInfo: any) => {
        const type = clickInfo.event.extendedProps.type;
        if (type === 'block') {
            if (confirm(`Delete this blocked slot: "${clickInfo.event.title}"?`)) {
                // Extract ID from "block-123"
                const id = clickInfo.event.id.replace('block-', '');
                handleDeleteBlock(id);
            }
        } else {
            // Booking details logic can go here (or open a modal)
            toast({
                title: clickInfo.event.title,
                description: `Location: ${clickInfo.event.extendedProps.location || 'Online'} - ${clickInfo.event.extendedProps.status}`,
            });
        }
    };

    const handleCreateBlock = async () => {
        if (!selectedDate) return;

        try {
            await apiClient.post('/pandits/me/calendar/', {
                start_time: selectedDate.start,
                end_time: selectedDate.end,
                title: blockReason
            });
            toast({ title: "Availability Updated", description: "Time slot marked as unavailable." });
            setIsDialogOpen(false);
            setBlockReason('Unavailable');
            fetchEvents(); // Refresh
        } catch (error) {
            toast({ title: "Error", description: "Failed to update availability", variant: "destructive" });
        }
    };

    const handleDeleteBlock = async (id: string) => {
        try {
            await apiClient.delete(`/pandits/me/calendar/blocks/${id}/`);
            toast({ title: "Success", description: "Availability block removed." });
            fetchEvents();
        } catch (error) {
            toast({ title: "Error", description: "Failed to remove block", variant: "destructive" });
        }
    };

    return (
        <Card className="h-full">
            <CardHeader className="flex flex-row items-center justify-between">
                <div>
                    <CardTitle>My Schedule</CardTitle>
                    <CardDescription>Manage your availability and view bookings</CardDescription>
                </div>
                <Button variant="outline" size="sm" onClick={fetchEvents}>
                    Refresh
                </Button>
            </CardHeader>
            <CardContent>
                {loading ? (
                    <div className="h-[500px] flex items-center justify-center">
                        <Loader2 className="h-8 w-8 animate-spin text-primary" />
                    </div>
                ) : (
                    <div className="calendar-container">
                        <style>{`
                    .fc-event { cursor: pointer; }
                    .fc-toolbar-title { font-size: 1.25rem !important; }
                    .fc-button { background-color: #f97316 !important; border-color: #f97316 !important; }
                    .fc-button:hover { background-color: #ea580c !important; border-color: #ea580c !important; }
                `}</style>
                        <FullCalendar
                            plugins={[dayGridPlugin, timeGridPlugin, interactionPlugin]}
                            initialView="timeGridWeek"
                            headerToolbar={{
                                left: 'prev,next today',
                                center: 'title',
                                right: 'dayGridMonth,timeGridWeek,timeGridDay'
                            }}
                            events={events} // Pass events here
                            selectable={true}
                            selectMirror={true}
                            select={handleDateSelect}
                            eventClick={handleEventClick}
                            height="auto"
                            slotMinTime="06:00:00"
                            slotMaxTime="22:00:00"
                            allDaySlot={false}
                        />
                    </div>
                )}
            </CardContent>

            {/* Block Dialog */}
            <Dialog open={isDialogOpen} onOpenChange={setIsDialogOpen}>
                <DialogContent>
                    <DialogHeader>
                        <DialogTitle>Mark Unavailable</DialogTitle>
                        <DialogDescription>
                            Block off this time slot on your calendar?
                        </DialogDescription>
                    </DialogHeader>
                    <div className="space-y-4 py-4">
                        <div className="space-y-2">
                            <Label>Reason (Optional)</Label>
                            <Input
                                value={blockReason}
                                onChange={(e) => setBlockReason(e.target.value)}
                                placeholder="e.g., Personal Time, Lunch"
                            />
                        </div>
                        {selectedDate && (
                            <div className="text-sm text-muted-foreground">
                                {format(new Date(selectedDate.start), 'PP p')} - {format(new Date(selectedDate.end), 'p')}
                            </div>
                        )}
                    </div>
                    <DialogFooter>
                        <Button variant="outline" onClick={() => setIsDialogOpen(false)}>Cancel</Button>
                        <Button onClick={handleCreateBlock}>Confirm Block</Button>
                    </DialogFooter>
                </DialogContent>
            </Dialog>
        </Card>
    );
};

import React, { useEffect, useState } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Input } from "@/components/ui/input";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter,
} from "@/components/ui/dialog";
import { useToast } from "@/hooks/use-toast";
import { Wallet, TrendingUp, History, ArrowDownToLine } from "lucide-react";
import apiClient from "@/lib/api-client";
import { format } from "date-fns";

interface WalletStats {
    total_earned: string;
    available_balance: string;
    total_withdrawn: string;
}

interface Withdrawal {
    id: number;
    amount: string;
    status: string;
    created_at: string;
}

export default function PanditEarnings() {
    const [wallet, setWallet] = useState<WalletStats>({
        total_earned: "0.00",
        available_balance: "0.00",
        total_withdrawn: "0.00"
    });
    const [withdrawals, setWithdrawals] = useState<Withdrawal[]>([]);
    const [loading, setLoading] = useState(true);
    const [requestAmount, setRequestAmount] = useState("");
    const [isWithdrawOpen, setIsWithdrawOpen] = useState(false);
    const { toast } = useToast();

    const loadData = async () => {
        setLoading(true);
        try {
            const [walletRes, historyRes] = await Promise.all([
                apiClient.get("/pandits/wallet/"),
                apiClient.get("/pandits/withdrawals/")
            ]);
            setWallet(walletRes.data);
            setWithdrawals(historyRes.data);
        } catch (error) {
            console.error("Failed to load earnings", error);
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        loadData();
    }, []);

    const handleWithdraw = async () => {
        const amount = parseFloat(requestAmount);
        if (isNaN(amount) || amount <= 0) {
            toast({ title: "Invalid Amount", description: "Please enter a valid positive number.", variant: "destructive" });
            return;
        }
        if (amount > parseFloat(wallet.available_balance)) {
            toast({ title: "Insufficient Funds", description: "You cannot withdraw more than your available balance.", variant: "destructive" });
            return;
        }

        try {
            await apiClient.post("/pandits/withdrawal/request/", { amount: amount });
            toast({ title: "Request Sent", description: "Your withdrawal request has been sent to admin for approval." });
            setIsWithdrawOpen(false);
            setRequestAmount("");
            loadData(); // Refresh data
        } catch (error: any) {
            toast({ 
                title: "Error", 
                description: error.response?.data?.error || "Failed to submit request", 
                variant: "destructive" 
            });
        }
    };

    return (
        <DashboardLayout userRole="pandit">
            <div className="space-y-6">
                <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight">My Earnings</h1>
                        <p className="text-muted-foreground">Track your income and request payouts.</p>
                    </div>

                    <Dialog open={isWithdrawOpen} onOpenChange={setIsWithdrawOpen}>
                        <DialogTrigger asChild>
                            <Button className="gap-2">
                                <ArrowDownToLine className="h-4 w-4" /> Withdraw Funds
                            </Button>
                        </DialogTrigger>
                        <DialogContent>
                            <DialogHeader>
                                <DialogTitle>Request Withdrawal</DialogTitle>
                                <DialogDescription>
                                    Enter the amount you wish to withdraw. Minimum Rs. 500.
                                </DialogDescription>
                            </DialogHeader>
                            <div className="space-y-4 py-4">
                                <div className="space-y-2">
                                    <div className="text-sm font-medium">Available Balance</div>
                                    <div className="text-2xl font-bold text-green-600">Rs. {wallet.available_balance}</div>
                                </div>
                                <div className="space-y-2">
                                    <label className="text-sm font-medium">Withdrawal Amount (Rs.)</label>
                                    <Input 
                                        type="number" 
                                        placeholder="Enter amount" 
                                        value={requestAmount}
                                        onChange={(e) => setRequestAmount(e.target.value)}
                                    />
                                </div>
                            </div>
                            <DialogFooter>
                                <Button variant="outline" onClick={() => setIsWithdrawOpen(false)}>Cancel</Button>
                                <Button onClick={handleWithdraw}>Submit Request</Button>
                            </DialogFooter>
                        </DialogContent>
                    </Dialog>
                </div>

                {/* Stats Cards */}
                <div className="grid gap-4 md:grid-cols-3">
                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Total Earned</CardTitle>
                            <TrendingUp className="h-4 w-4 text-green-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">Rs. {wallet.total_earned}</div>
                            <p className="text-xs text-muted-foreground">Lifetime earnings from bookings</p>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Available Balance</CardTitle>
                            <Wallet className="h-4 w-4 text-blue-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold text-blue-600">Rs. {wallet.available_balance}</div>
                            <p className="text-xs text-muted-foreground">Available for withdrawal</p>
                        </CardContent>
                    </Card>
                    <Card>
                        <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                            <CardTitle className="text-sm font-medium">Total Withdrawn</CardTitle>
                            <History className="h-4 w-4 text-gray-600" />
                        </CardHeader>
                        <CardContent>
                            <div className="text-2xl font-bold">Rs. {wallet.total_withdrawn}</div>
                            <p className="text-xs text-muted-foreground">Total payout processed</p>
                        </CardContent>
                    </Card>
                </div>

                {/* Transaction History */}
                <Card>
                    <CardHeader>
                        <CardTitle>Withdrawal History</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Date</TableHead>
                                    <TableHead>Amount</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead className="text-right">Transaction ID</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {withdrawals.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={4} className="text-center h-24 text-muted-foreground">
                                            No withdrawal requests found.
                                        </TableCell>
                                    </TableRow>
                                ) : (
                                    withdrawals.map((w) => (
                                        <TableRow key={w.id}>
                                            <TableCell>{format(new Date(w.created_at), "MMM dd, yyyy")}</TableCell>
                                            <TableCell className="font-medium">Rs. {w.amount}</TableCell>
                                            <TableCell>
                                                <Badge variant={
                                                    w.status === "APPROVED" ? "default" : 
                                                    w.status === "REJECTED" ? "destructive" : "secondary"
                                                }>
                                                    {w.status}
                                                </Badge>
                                            </TableCell>
                                            <TableCell className="text-right font-mono text-xs">#{w.id}</TableCell>
                                        </TableRow>
                                    ))
                                )}
                            </TableBody>
                        </Table>
                    </CardContent>
                </Card>
            </div>
        </DashboardLayout>
    );
}

import React, { useEffect, useState, useRef } from 'react';
import { DashboardLayout } from '@/components/layout/DashboardLayout';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Input } from '@/components/ui/input';
import { Badge } from '@/components/ui/badge';
import { Avatar, AvatarFallback, AvatarImage } from '@/components/ui/avatar';
import { MessageCircle, Send, User, Clock, Search } from 'lucide-react';
import api from '@/lib/api-client';
import { useAuth } from '@/hooks/useAuth';
import { formatDistanceToNow } from 'date-fns';

interface ChatRoom {
  id: number;
  user: {
    id: number;
    full_name: string;
    profile_picture?: string;
  };
  last_message?: string;
  last_message_time?: string;
  unread_count: number;
  is_pre_booking: boolean;
  booking?: {
    id: number;
    service_name: string;
    status: string;
  };
}

interface Message {
  id: number;
  content: string;
  sender: 'user' | 'pandit';
  sender_name: string;
  timestamp: string;
  is_read: boolean;
}

const PanditMessages: React.FC = () => {
  const { token } = useAuth();
  const [chatRooms, setChatRooms] = useState<ChatRoom[]>([]);
  const [selectedRoom, setSelectedRoom] = useState<ChatRoom | null>(null);
  const [messages, setMessages] = useState<Message[]>([]);
  const [newMessage, setNewMessage] = useState('');
  const [loading, setLoading] = useState(true);
  const [sendingMessage, setSendingMessage] = useState(false);
  const [searchQuery, setSearchQuery] = useState('');
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const wsRef = useRef<WebSocket | null>(null);

  // Fetch chat rooms
  useEffect(() => {
    fetchChatRooms();
  }, []);

  // Auto-scroll to bottom when messages change
  useEffect(() => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages]);

  // Connect WebSocket when room is selected
  useEffect(() => {
    if (selectedRoom && token) {
      connectWebSocket(selectedRoom.id);
      fetchMessages(selectedRoom.id);
    }

    return () => {
      if (wsRef.current) {
        wsRef.current.close();
      }
    };
  }, [selectedRoom, token]);

  const fetchChatRooms = async () => {
    try {
      const response = await api.get('/chat/rooms/');
      setChatRooms(response.data.results || response.data);
    } catch (error) {
      console.error('Failed to fetch chat rooms:', error);
    } finally {
      setLoading(false);
    }
  };

  const fetchMessages = async (roomId: number) => {
    try {
      const response = await api.get(`/chat/rooms/${roomId}/messages/`);
      setMessages(response.data.results || response.data);
    } catch (error) {
      console.error('Failed to fetch messages:', error);
    }
  };

  const connectWebSocket = (roomId: number) => {
    if (wsRef.current) {
      wsRef.current.close();
    }

    const wsBaseUrl = import.meta.env.VITE_WS_URL || 'ws://localhost:8000';
    const wsUrl = `${wsBaseUrl}/ws/chat/${roomId}/?token=${encodeURIComponent(token || '')}`;

    wsRef.current = new WebSocket(wsUrl);

    wsRef.current.onopen = () => {
      console.log('WebSocket connected');
    };

    wsRef.current.onmessage = (event) => {
      try {
        const data = JSON.parse(event.data);
        if (data.type === 'message') {
          const messageData = data.data;
          setMessages((prev) => [
            ...prev,
            {
              id: messageData.id,
              content: messageData.content,
              sender: messageData.sender,
              sender_name: messageData.sender_name,
              timestamp: messageData.timestamp,
              is_read: true,
            },
          ]);
          // Update chat room's last message
          setChatRooms((prev) =>
            prev.map((room) =>
              room.id === selectedRoom?.id
                ? { ...room, last_message: messageData.content, last_message_time: messageData.timestamp }
                : room
            )
          );
        } else if (data.type === 'message_history') {
          setMessages(data.messages || []);
        }
      } catch (error) {
        console.error('Error parsing WebSocket message:', error);
      }
    };

    wsRef.current.onerror = (error) => {
      console.error('WebSocket error:', error);
    };

    wsRef.current.onclose = () => {
      console.log('WebSocket disconnected');
    };
  };

  const sendMessage = async () => {
    if (!newMessage.trim() || !selectedRoom) return;

    setSendingMessage(true);
    try {
      // Try WebSocket first
      if (wsRef.current && wsRef.current.readyState === WebSocket.OPEN) {
        wsRef.current.send(
          JSON.stringify({
            type: 'message',
            content: newMessage,
          })
        );
      } else {
        // Fallback to HTTP
        await api.post(`/chat/rooms/${selectedRoom.id}/messages/`, {
          content: newMessage,
        });
        // Refresh messages
        fetchMessages(selectedRoom.id);
      }
      setNewMessage('');
    } catch (error) {
      console.error('Failed to send message:', error);
    } finally {
      setSendingMessage(false);
    }
  };

  const handleKeyPress = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault();
      sendMessage();
    }
  };

  const filteredRooms = chatRooms.filter((room) =>
    room.user.full_name.toLowerCase().includes(searchQuery.toLowerCase())
  );

  const formatTime = (timestamp: string) => {
    try {
      return formatDistanceToNow(new Date(timestamp), { addSuffix: true });
    } catch {
      return timestamp;
    }
  };

  return (
    <DashboardLayout userRole="pandit">
      <div className="space-y-6">
        <div>
          <h1 className="text-3xl font-bold tracking-tight">Messages</h1>
          <p className="text-muted-foreground">Chat with your customers and respond to inquiries.</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 h-[calc(100vh-220px)]">
          {/* Chat List */}
          <Card className="md:col-span-1 flex flex-col">
            <CardHeader className="pb-3">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-muted-foreground" />
                <Input
                  placeholder="Search conversations..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="pl-9"
                />
              </div>
            </CardHeader>
            <CardContent className="flex-1 p-0 overflow-hidden">
              <div className="h-full overflow-y-auto">
                {loading ? (
                  <div className="p-4 text-center text-muted-foreground">Loading...</div>
                ) : filteredRooms.length === 0 ? (
                  <div className="p-4 text-center text-muted-foreground">
                    <MessageCircle className="h-12 w-12 mx-auto mb-2 opacity-50" />
                    <p>No conversations yet</p>
                    <p className="text-sm">When users message you, they'll appear here</p>
                  </div>
                ) : (
                  <div className="divide-y">
                    {filteredRooms.map((room) => (
                      <div
                        key={room.id}
                        className={`p-4 cursor-pointer hover:bg-accent transition-colors ${
                          selectedRoom?.id === room.id ? 'bg-accent' : ''
                        }`}
                        onClick={() => setSelectedRoom(room)}
                      >
                        <div className="flex items-start gap-3">
                          <Avatar className="h-10 w-10">
                            <AvatarImage src={room.user.profile_picture} />
                            <AvatarFallback>
                              <User className="h-5 w-5" />
                            </AvatarFallback>
                          </Avatar>
                          <div className="flex-1 min-w-0">
                            <div className="flex items-center justify-between">
                              <p className="font-medium truncate">{room.user.full_name}</p>
                              {room.unread_count > 0 && (
                                <Badge variant="default" className="ml-2 bg-primary">
                                  {room.unread_count}
                                </Badge>
                              )}
                            </div>
                            <div className="flex items-center gap-2">
                              {room.is_pre_booking ? (
                                <Badge variant="outline" className="text-xs">Pre-booking</Badge>
                              ) : room.booking ? (
                                <Badge variant="secondary" className="text-xs">
                                  {room.booking.service_name}
                                </Badge>
                              ) : null}
                            </div>
                            {room.last_message && (
                              <p className="text-sm text-muted-foreground truncate mt-1">
                                {room.last_message}
                              </p>
                            )}
                            {room.last_message_time && (
                              <p className="text-xs text-muted-foreground flex items-center gap-1 mt-1">
                                <Clock className="h-3 w-3" />
                                {formatTime(room.last_message_time)}
                              </p>
                            )}
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            </CardContent>
          </Card>

          {/* Chat Window */}
          <Card className="md:col-span-2 flex flex-col">
            {selectedRoom ? (
              <>
                <CardHeader className="border-b pb-4">
                  <div className="flex items-center gap-3">
                    <Avatar className="h-10 w-10">
                      <AvatarImage src={selectedRoom.user.profile_picture} />
                      <AvatarFallback>
                        <User className="h-5 w-5" />
                      </AvatarFallback>
                    </Avatar>
                    <div>
                      <CardTitle className="text-lg">{selectedRoom.user.full_name}</CardTitle>
                      <div className="flex items-center gap-2">
                        {selectedRoom.is_pre_booking ? (
                          <Badge variant="outline" className="text-xs">Pre-booking Inquiry</Badge>
                        ) : selectedRoom.booking ? (
                          <Badge variant="secondary" className="text-xs">
                            Booking: {selectedRoom.booking.service_name}
                          </Badge>
                        ) : null}
                      </div>
                    </div>
                  </div>
                </CardHeader>
                <CardContent className="flex-1 p-0 overflow-hidden flex flex-col">
                  <div className="flex-1 p-4 overflow-y-auto">
                    <div className="space-y-4">
                      {messages.map((message) => (
                        <div
                          key={message.id}
                          className={`flex ${message.sender === 'pandit' ? 'justify-end' : 'justify-start'}`}
                        >
                          <div
                            className={`max-w-[70%] rounded-lg px-4 py-2 ${
                              message.sender === 'pandit'
                                ? 'bg-primary text-primary-foreground'
                                : 'bg-muted'
                            }`}
                          >
                            <p className="text-sm">{message.content}</p>
                            <p
                              className={`text-xs mt-1 ${
                                message.sender === 'pandit' ? 'text-primary-foreground/70' : 'text-muted-foreground'
                              }`}
                            >
                              {formatTime(message.timestamp)}
                            </p>
                          </div>
                        </div>
                      ))}
                      <div ref={messagesEndRef} />
                    </div>
                  </div>
                  <div className="p-4 border-t">
                    <div className="flex gap-2">
                      <Input
                        placeholder="Type a message..."
                        value={newMessage}
                        onChange={(e) => setNewMessage(e.target.value)}
                        onKeyPress={handleKeyPress}
                        disabled={sendingMessage}
                      />
                      <Button onClick={sendMessage} disabled={sendingMessage || !newMessage.trim()}>
                        <Send className="h-4 w-4" />
                      </Button>
                    </div>
                  </div>
                </CardContent>
              </>
            ) : (
              <CardContent className="flex-1 flex items-center justify-center">
                <div className="text-center text-muted-foreground">
                  <MessageCircle className="h-16 w-16 mx-auto mb-4 opacity-50" />
                  <h3 className="text-lg font-medium">Select a conversation</h3>
                  <p className="text-sm">Choose a conversation from the list to start chatting</p>
                </div>
              </CardContent>
            )}
          </Card>
        </div>
      </div>
    </DashboardLayout>
  );
};

export default PanditMessages;

import React, { useState, useEffect } from 'react'
import { DashboardLayout } from '@/components/layout/DashboardLayout'
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Button } from "@/components/ui/button"
import { Input } from "@/components/ui/input"
import { Label } from "@/components/ui/label"
import { Textarea } from "@/components/ui/textarea"
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar"
import { Camera } from "lucide-react"
import { useAuth } from '@/hooks/useAuth';
import { useToast } from '@/hooks/use-toast';
import { deletePanditProfile, updatePanditProfile } from '@/lib/api';
import { zodResolver } from "@hookform/resolvers/zod"
import { useForm } from "react-hook-form"
import * as z from "zod"
import { useNavigate } from 'react-router-dom';
import { ActionConfirmationDialog } from '@/components/common/ActionConfirmationDialog';
import {
    Form,
    FormControl,
    FormField,
    FormItem,
    FormLabel,
    FormMessage,
} from "@/components/ui/form"

const profileFormSchema = z.object({
    full_name: z.string().min(2, {
        message: "Full name must be at least 2 characters.",
    }),
    phone_number: z.string().min(10, {
        message: "Phone number must be at least 10 digits.",
    }),
    expertise: z.string().min(2, {
        message: "Expertise must be at least 2 characters.",
    }),
    language: z.string().min(2, {
        message: "Language must be at least 2 characters.",
    }),
    experience_years: z.coerce.number().min(0, {
        message: "Experience must be a positive number.",
    }),
    bio: z.string().max(500, {
        message: "Bio must not be longer than 500 characters.",
    }).min(10, {
        message: "Bio must be at least 10 characters.",
    }),
    profile_pic: z.any().optional(),
    certification_file: z.any().optional(),
})

type ProfileFormValues = z.infer<typeof profileFormSchema>


const PanditProfile = () => {
    const [photoPreview, setPhotoPreview] = useState<string | null>(null);
    const { user, refreshUser } = useAuth();
    const { toast } = useToast();
    const navigate = useNavigate();
    const [isSaving, setIsSaving] = useState(false);
    const [isDeleting, setIsDeleting] = useState(false);
    const [showDeleteDialog, setShowDeleteDialog] = useState(false);

    const form = useForm<ProfileFormValues>({
        resolver: zodResolver(profileFormSchema) as any,
        defaultValues: {
            full_name: user?.full_name || "",
            phone_number: user?.phone_number || "",
            expertise: user?.pandit_profile?.expertise || "",
            language: user?.pandit_profile?.language || "",
            experience_years: user?.pandit_profile?.experience_years || 0,
            bio: user?.pandit_profile?.bio || "",
            certification_file: undefined,
        },
        mode: "onChange",
    })


    useEffect(() => {
        if (user) {
            form.reset({
                full_name: user.full_name || "",
                phone_number: user.phone_number || "",
                expertise: user.pandit_profile?.expertise || "",
                language: user.pandit_profile?.language || "",
                experience_years: user.pandit_profile?.experience_years || 0,
                bio: user.pandit_profile?.bio || "",
            });
            setPhotoPreview(user.profile_pic || null);
        }
    }, [user, form]);

    const handlePhotoChange = (e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (file) {
            const reader = new FileReader();
            reader.onloadend = () => {
                setPhotoPreview(reader.result as string);
            };
            reader.readAsDataURL(file);
            form.setValue('profile_pic', file);
        }
    };

    async function onSubmit(data: ProfileFormValues) {
        if (!user || (!user.pandit_profile && user.role !== 'pandit')) {
            toast({
                title: "Error",
                description: "Not authenticated or no pandit profile found.",
                variant: "destructive",
            });
            return;
        }

        setIsSaving(true);
        try {
            const formData = new FormData();

            // Append nested user fields
            formData.append('user_data.full_name', data.full_name);
            formData.append('user_data.phone_number', data.phone_number);

            // Append Pandit fields
            formData.append('expertise', data.expertise);
            formData.append('language', data.language);
            formData.append('experience_years', String(data.experience_years));
            formData.append('bio', data.bio);

            if (data.certification_file instanceof File) {
                formData.append('certification_file', data.certification_file);
            }

            if (data.profile_pic instanceof File) {
                formData.append('user_data.profile_pic', data.profile_pic);
            }

            if (user.pandit_profile) {
                await updatePanditProfile(user.pandit_profile.id, formData);
            } else {
                throw new Error("Pandit Profile ID missing");
            }

            // Update user context
            if (refreshUser) {
                await refreshUser();
            }

            toast({
                title: "Success",
                description: "Your profile has been updated successfully.",
            });
        } catch (error) {
            console.error("Profile update failed:", error);
            toast({
                title: "Update Failed",
                description: "Could not update your profile. Please try again.",
                variant: "destructive",
            });
        } finally {
            setIsSaving(false);
        }
    }

    const handleDeletePanditProfile = async () => {
        if (!user?.pandit_profile?.id) {
            toast({
                title: 'Delete Failed',
                description: 'Pandit profile not found.',
                variant: 'destructive',
            });
            return;
        }

        setIsDeleting(true);
        try {
            await deletePanditProfile(user.pandit_profile.id);

            if (refreshUser) {
                await refreshUser();
            }

            toast({
                title: 'Profile Deleted',
                description: 'Pandit profile deleted. Your account is now a normal user account.',
            });

            navigate('/profile');
        } catch (error) {
            toast({
                title: 'Delete Failed',
                description: 'Could not delete pandit profile. Please try again.',
                variant: 'destructive',
            });
        } finally {
            setIsDeleting(false);
            setShowDeleteDialog(false);
        }
    };

    return (
        <DashboardLayout userRole="pandit">
            <Form {...form}>
                <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6 max-w-2xl">
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight">My Profile</h1>
                        <p className="text-muted-foreground">Manage your personal information and expertise.</p>
                    </div>

                    <Card>
                        <CardHeader>
                            <CardTitle>Personal Details</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-6">
                            {/* Photo Upload Section */}
                            <div className="flex flex-col items-center gap-4 mb-4">
                                <div className="relative">
                                    <Avatar className="h-32 w-32 border-4 border-white shadow-lg bg-gray-100">
                                        <AvatarImage src={photoPreview || ""} className="object-cover" />
                                        <AvatarFallback className="text-4xl text-gray-400">
                                            {user?.full_name?.[0] || 'P'}
                                        </AvatarFallback>
                                    </Avatar>
                                    <label
                                        htmlFor="photo-upload"
                                        className="absolute -bottom-2 -right-2 cursor-pointer bg-orange-600 text-white rounded-full p-2 hover:bg-orange-700 transition-colors"
                                    >
                                        <Camera size={20} />
                                    </label>
                                    <Input
                                        id="photo-upload"
                                        type="file"
                                        className="hidden"
                                        accept="image/png, image/jpeg, image/jpg"
                                        onChange={handlePhotoChange}
                                    />
                                </div>
                                <p className="text-xs text-muted-foreground">Allowed: JPG, PNG. Max size: 2MB</p>
                            </div>

                            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                                <FormField
                                    control={form.control}
                                    name="full_name"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Full Name</FormLabel>
                                            <FormControl>
                                                <Input placeholder="Rajesh Shastri" {...field} />
                                            </FormControl>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />
                                <FormField
                                    control={form.control}
                                    name="phone_number"
                                    render={({ field }) => (
                                        <FormItem>
                                            <FormLabel>Phone Number</FormLabel>
                                            <FormControl>
                                                <Input placeholder="+977" {...field} />
                                            </FormControl>
                                            <FormMessage />
                                        </FormItem>
                                    )}
                                />
                            </div>
                            <div className="space-y-2">
                                <Label>Email</Label>
                                <Input value={user?.email || ""} placeholder="email@example.com" disabled />
                            </div>
                        </CardContent>
                    </Card>

                    <Card>
                        <CardHeader>
                            <CardTitle>Professional Info</CardTitle>
                        </CardHeader>
                        <CardContent className="space-y-4">
                            <FormField
                                control={form.control}
                                name="expertise"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Expertise (Comma separated)</FormLabel>
                                        <FormControl>
                                            <Input placeholder="e.g. Vastu, Astrology, Wedding" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="language"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Languages</FormLabel>
                                        <FormControl>
                                            <Input placeholder="e.g. Hindi, Sanskrit, English" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="experience_years"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Years of Experience</FormLabel>
                                        <FormControl>
                                            <Input type="number" placeholder="5" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />
                            <FormField
                                control={form.control}
                                name="bio"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Bio</FormLabel>
                                        <FormControl>
                                            <Textarea placeholder="Tell us about yourself..." className="h-32" {...field} />
                                        </FormControl>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <FormField
                                control={form.control}
                                name="certification_file"
                                render={({ field }) => (
                                    <FormItem>
                                        <FormLabel>Certification Upload</FormLabel>
                                        <FormControl>
                                            <Input
                                                type="file"
                                                accept=".pdf,.jpg,.jpeg,.png"
                                                onChange={(e) => {
                                                    const file = e.target.files?.[0];
                                                    field.onChange(file || undefined);
                                                }}
                                            />
                                        </FormControl>
                                        <p className="text-xs text-muted-foreground">Accepted: PDF, JPG, PNG</p>
                                        <FormMessage />
                                    </FormItem>
                                )}
                            />

                            <div className="flex flex-col sm:flex-row gap-3">
                            <Button type="submit" disabled={isSaving || isDeleting}>
                                {isSaving ? "Saving..." : "Save Changes"}
                            </Button>
                            <Button
                                type="button"
                                variant="destructive"
                                disabled={isSaving || isDeleting}
                                onClick={() => setShowDeleteDialog(true)}
                            >
                                {isDeleting ? 'Deleting...' : 'Delete Pandit Profile'}
                            </Button>
                            </div>

                            <ActionConfirmationDialog
                                open={showDeleteDialog}
                                onOpenChange={setShowDeleteDialog}
                                onConfirm={handleDeletePanditProfile}
                                title="Delete Pandit Profile?"
                                description="Are you sure you want to delete your pandit profile from PanditYatra? Your account will remain as a normal user account."
                                confirmLabel="Yes, Delete"
                                isLoading={isDeleting}
                            />
                        </CardContent>
                    </Card>
                </form>
            </Form>
        </DashboardLayout>
    )
}

export default PanditProfile

import React, { useEffect, useState } from "react";
import { DashboardLayout } from "@/components/layout/DashboardLayout";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Badge } from "@/components/ui/badge";
import {
    Table,
    TableBody,
    TableCell,
    TableHead,
    TableHeader,
    TableRow,
} from "@/components/ui/table";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import {
    Dialog,
    DialogContent,
    DialogDescription,
    DialogHeader,
    DialogTitle,
    DialogTrigger,
    DialogFooter,
} from "@/components/ui/dialog";
import {
    Select,
    SelectContent,
    SelectItem,
    SelectTrigger,
    SelectValue,
} from "@/components/ui/select";
import { Switch } from "@/components/ui/switch";
import { Label } from "@/components/ui/label";
import { useToast } from "@/hooks/use-toast";
import { Plus, Trash2, Loader2, IndianRupee } from "lucide-react";
import apiClient from "@/lib/api-client";

interface PanditService {
    id: number;
    puja_details: {
        id: number;
        name: string;
        description: string;
        base_price: string;
        base_duration_minutes: number;
    };
    custom_price: string;
    duration_minutes: number;
    is_active: boolean;
    is_online: boolean;
    is_offline: boolean;
}

interface Puja {
    id: number;
    name: string;
    description: string;
    base_price: string;
    base_duration_minutes: number;
}

export default function PanditServices() {
    const { toast } = useToast();
    const [services, setServices] = useState<PanditService[]>([]);
    const [availablePujas, setAvailablePujas] = useState<Puja[]>([]);
    const [loading, setLoading] = useState(true);
    const [isAddOpen, setIsAddOpen] = useState(false);

    // Form State
    const [selectedPujaId, setSelectedPujaId] = useState<string>("");
    const [price, setPrice] = useState("");
    const [duration, setDuration] = useState("");
    const [isOnline, setIsOnline] = useState(false);
    const [isOffline, setIsOffline] = useState(true);
    const [isActive, setIsActive] = useState(true);

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        try {
            const [servicesRes, catalogRes] = await Promise.all([
                apiClient.get("/pandits/my-services/"),
                apiClient.get("/pandits/services/catalog/")
            ]);
            setServices(servicesRes.data);
            setAvailablePujas(catalogRes.data);
        } catch (error) {
            console.error("Error fetching services", error);
            toast({
                title: "Error",
                description: "Failed to load services",
                variant: "destructive",
            });
        } finally {
            setLoading(false);
        }
    };

    const handleAddService = async () => {
        if (!selectedPujaId || !price || !duration) {
            toast({ title: "Error", description: "All fields are required", variant: "destructive" });
            return;
        }

        try {
            await apiClient.post("/pandits/my-services/", {
                puja_id: selectedPujaId,
                custom_price: price,
                duration_minutes: duration,
                is_online: isOnline,
                is_offline: isOffline,
                is_active: isActive
            });

            toast({ title: "Success", description: "Service added successfully" });
            setIsAddOpen(false);
            fetchData(); // Refresh

            // Reset form
            setSelectedPujaId("");
            setPrice("");
            setDuration("");
            setIsActive(true);
        } catch (error: any) {
            // ... error handling
        }
    };

    // Edit State
    const [editServiceId, setEditServiceId] = useState<number | null>(null);

    const handleEdit = (service: PanditService) => {
        setEditServiceId(service.id);
        setSelectedPujaId(service.puja_details.id.toString());
        setPrice(service.custom_price);
        setDuration(service.duration_minutes.toString());
        setIsOnline(service.is_online);
        setIsOffline(service.is_offline);
        setIsActive(service.is_active);
        setIsAddOpen(true);
    };

    const handleSaveService = async () => {
        if (!selectedPujaId || !price || !duration) {
            toast({ title: "Error", description: "All fields are required", variant: "destructive" });
            return;
        }

        try {
            const payload = {
                puja_id: selectedPujaId,
                custom_price: price,
                duration_minutes: duration,
                is_online: isOnline,
                is_offline: isOffline,
                is_active: isActive
            };

            if (editServiceId) {
                // Update existing
                await apiClient.patch(`/pandits/my-services/${editServiceId}/`, payload);
                toast({ title: "Success", description: "Service updated successfully" });
            } else {
                // Create new
                await apiClient.post("/pandits/my-services/", payload);
                toast({ title: "Success", description: "Service added successfully" });
            }
            // ... rest of the function

            setIsAddOpen(false);
            setEditServiceId(null);
            fetchData(); // Refresh

            // Reset form
            setSelectedPujaId("");
            setPrice("");
            setDuration("");
        } catch (error: any) {
            toast({
                title: "Error",
                description: error.response?.data?.detail || "Failed to save service",
                variant: "destructive"
            });
        }
    };

    const handleToggleActive = async (id: number, currentStatus: boolean) => {
        try {
            // Optimistic update
            setServices(services.map(s => s.id === id ? { ...s, is_active: !currentStatus } : s));

            await apiClient.patch(`/pandits/my-services/${id}/`, { is_active: !currentStatus });
            toast({ title: "Success", description: `Service ${!currentStatus ? 'activated' : 'deactivated'}` });
        } catch (error) {
            // Revert on error
            setServices(services.map(s => s.id === id ? { ...s, is_active: currentStatus } : s));
            toast({ title: "Error", description: "Failed to update status", variant: "destructive" });
        }
    };

    const handleDelete = async (id: number) => {
        if (!confirm("Are you sure you want to remove this service?")) return;
        try {
            await apiClient.delete(`/pandits/my-services/${id}/`);
            toast({ title: "Success", description: "Service removed" });
            setServices(services.filter(s => s.id !== id));
        } catch (error) {
            toast({ title: "Error", description: "Failed to remove service", variant: "destructive" });
        }
    };

    // Helper to auto-fill defaults when puja selected
    const onPujaSelect = (val: string) => {
        setSelectedPujaId(val);
        const puja = availablePujas.find(p => p.id.toString() === val);
        if (puja) {
            setPrice(puja.base_price);
            setDuration(puja.base_duration_minutes.toString());
        }
    };

    const handleDialogClose = (open: boolean) => {
        setIsAddOpen(open);
        if (!open) {
            setEditServiceId(null);
            setSelectedPujaId("");
            setPrice("");
            setDuration("");
        }
    };

    if (loading) return <div className="flex justify-center p-8"><Loader2 className="animate-spin" /></div>;

    return (
        <DashboardLayout userRole="pandit">
            <div className="space-y-6">
                <div className="flex justify-between items-center">
                    <div>
                        <h1 className="text-3xl font-bold tracking-tight">My Services</h1>
                        <p className="text-muted-foreground">Manage the Pujas you offer and your pricing.</p>
                    </div>
                    <Dialog open={isAddOpen} onOpenChange={handleDialogClose}>
                        <DialogTrigger asChild>
                            <Button><Plus className="mr-2 h-4 w-4" /> Add Service</Button>
                        </DialogTrigger>
                        <DialogContent>
                            <DialogHeader>
                                <DialogTitle>{editServiceId ? 'Edit Service' : 'Add New Service'}</DialogTitle>
                                <DialogDescription>
                                    {editServiceId ? 'Update your service details.' : 'Select a Puja from the catalog to offer.'}
                                </DialogDescription>
                            </DialogHeader>
                            <div className="space-y-4 py-4">
                                <div className="space-y-2">
                                    <Label>Puja Type</Label>
                                    <Select
                                        value={selectedPujaId}
                                        onValueChange={onPujaSelect}
                                        disabled={!!editServiceId} // Disable changing puja type on edit
                                    >
                                        <SelectTrigger>
                                            <SelectValue placeholder="Select Puja" />
                                        </SelectTrigger>
                                        <SelectContent>
                                            {availablePujas.map(p => (
                                                <SelectItem key={p.id} value={p.id.toString()}>
                                                    {p.name} (Base: ₹{p.base_price})
                                                </SelectItem>
                                            ))}
                                        </SelectContent>
                                    </Select>
                                </div>

                                <div className="grid grid-cols-2 gap-4">
                                    <div className="space-y-2">
                                        <Label>Your Price (₹)</Label>
                                        <Input
                                            type="number"
                                            value={price}
                                            onChange={e => setPrice(e.target.value)}
                                        />
                                    </div>
                                    <div className="space-y-2">
                                        <Label>Duration (Minutes)</Label>
                                        <Input
                                            type="number"
                                            value={duration}
                                            onChange={e => setDuration(e.target.value)}
                                        />
                                    </div>
                                </div>

                                <div className="flex items-center space-x-4">
                                    <div className="flex items-center space-x-2">
                                        <Switch checked={isOnline} onCheckedChange={setIsOnline} id="online-mode" />
                                        <Label htmlFor="online-mode">Online</Label>
                                    </div>
                                    <div className="flex items-center space-x-2">
                                        <Switch checked={isOffline} onCheckedChange={setIsOffline} id="offline-mode" />
                                        <Label htmlFor="offline-mode">In-Person</Label>
                                    </div>
                                </div>
                            </div>
                            <DialogFooter>
                                <Button variant="outline" onClick={() => handleDialogClose(false)}>Cancel</Button>
                                <Button onClick={handleSaveService}>{editServiceId ? 'Update Service' : 'Save Service'}</Button>
                            </DialogFooter>
                        </DialogContent>
                    </Dialog>
                </div>

                <Card>
                    <CardHeader>
                        <CardTitle>Active Services ({services.length})</CardTitle>
                    </CardHeader>
                    <CardContent>
                        <Table>
                            <TableHeader>
                                <TableRow>
                                    <TableHead>Service Name</TableHead>
                                    <TableHead>Price</TableHead>
                                    <TableHead>Duration</TableHead>
                                    <TableHead>Modes</TableHead>
                                    <TableHead>Status</TableHead>
                                    <TableHead className="text-right">Actions</TableHead>
                                </TableRow>
                            </TableHeader>
                            <TableBody>
                                {services.length === 0 ? (
                                    <TableRow>
                                        <TableCell colSpan={6} className="text-center py-8 text-muted-foreground">
                                            No services added yet. Click "Add Service" to start earning.
                                        </TableCell>
                                    </TableRow>
                                ) : (
                                    services.map((service) => (
                                        <TableRow key={service.id}>
                                            <TableCell className="font-medium">
                                                {service.puja_details.name}
                                                <div className="text-xs text-muted-foreground line-clamp-1">{service.puja_details.description}</div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex items-center">
                                                    <IndianRupee className="h-3 w-3 mr-1" />
                                                    {service.custom_price}
                                                </div>
                                            </TableCell>
                                            <TableCell>{service.duration_minutes} mins</TableCell>
                                            <TableCell>
                                                <div className="flex gap-2">
                                                    {service.is_online && <Badge variant="secondary">Online</Badge>}
                                                    {service.is_offline && <Badge variant="default">In-Person</Badge>}
                                                </div>
                                            </TableCell>
                                            <TableCell>
                                                <div className="flex items-center gap-2">
                                                    <Switch
                                                        checked={service.is_active}
                                                        onCheckedChange={() => handleToggleActive(service.id, service.is_active)}
                                                    />
                                                    <span className={`text-xs ${service.is_active ? 'text-green-600' : 'text-gray-400'}`}>
                                                        {service.is_active ? 'Active' : 'Inactive'}
                                                    </span>
                                                </div>
                                            </TableCell>
                                            <TableCell className="text-right">
                                                <div className="flex justify-end gap-2">
                                                    <Button variant="outline" size="sm" onClick={() => handleEdit(service)}>
                                                        Edit
                                                    </Button>
                                                    <Button variant="ghost" size="icon" onClick={() => handleDelete(service.id)}>
                                                        <Trash2 className="h-4 w-4 text-red-500" />
                                                    </Button>
                                                </div>
                                            </TableCell>
                                        </TableRow>
                                    ))
                                )}
                            </TableBody>
                        </Table>
                    </CardContent>
                </Card>
            </div>
        </DashboardLayout>
    );
}

import axios from 'axios';

const API_BASE_URL = 'http://localhost:8000/api';

const apiClient = axios.create({
  baseURL: API_BASE_URL,
  headers: {
    'Content-Type': 'application/json',
  },
});

// Add token to requests if available
apiClient.interceptors.request.use((config) => {
  const token = localStorage.getItem('token');
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export const api = apiClient;

export const fetchPujas = async () => {
  try {
    const response = await apiClient.get('/services/');
    return response.data;
  } catch (error) {
    console.error('Error fetching pujas:', error);
    throw error;
  }
};

export const fetchPujaById = async (id: number) => {
  try {
    const response = await apiClient.get(`/services/${id}/`);
    return response.data;
  } catch (error) {
    console.error(`Error fetching puja ${id}:`, error);
    throw error;
  }
};

// Video call related API calls
export const createVideoRoom = async (bookingId: number) => {
  const response = await api.get(`/video/room/${bookingId}/`);
  return response.data
};

export const fetchPanditServices = async (panditId: number) => {
  try {
    const response = await apiClient.get(`/pandits/${panditId}/services/`);
    return response.data;
  } catch (error) {
    console.error(`Error fetching services for pandit ${panditId}:`, error);
    throw error;
  }
};

export const fetchPanchang = async (date?: string, days: number = 1) => {
  try {
    const params: any = { days };
    if (date) params.date = date;
    const response = await apiClient.get('/panchang/data/', { params });
    return response.data;
  } catch (error) {
    console.error('Error fetching panchang:', error);
    throw error;
  }
};

export default apiClient;
